export enum TimeFrame {
  DAILY = 'DAILY',
  WEEKLY = 'WEEKLY',
  MONTHLY = 'MONTHLY',
  ALL_TIME = 'ALL_TIME'
}

export interface RawDataRow {
  player: string;
  ks: number;
  date: string; // ISO string or simple date string
}

export interface RankedPlayer {
  rank: number;
  name: string;
  totalKS: number;
  gamesPlayed: number;
  averageKS: number;
  trend: 'up' | 'down' | 'same'; // Visual indicator
}

export interface RankingData {
  timeFrame: TimeFrame;
  lastUpdated: string;
  players: RankedPlayer[];
}

import { RawDataRow, RankedPlayer, TimeFrame } from '../types';

const SHEET_URL = 'https://docs.google.com/spreadsheets/d/e/2PACX-1vQkJhKP1MWxMqBupRr3TmzbsuoZHF2ljzRG1lMCjZ--46ON-vVoPf4mgn5PqjmiWtOpphpmkPYFeYLK/pub?output=csv';

// Fallback data in case the fetch fails (CORS or empty)
const MOCK_DATA: RawDataRow[] = [
  { player: "NeonViper", ks: 15, date: new Date().toISOString() },
  { player: "NeonViper", ks: 12, date: new Date(Date.now() - 86400000).toISOString() },
  { player: "CyberGhost", ks: 22, date: new Date().toISOString() },
  { player: "CyberGhost", ks: 5, date: new Date(Date.now() - 86400000 * 3).toISOString() },
  { player: "GlitchMaster", ks: 8, date: new Date().toISOString() },
  { player: "GlitchMaster", ks: 45, date: new Date(Date.now() - 86400000 * 10).toISOString() },
  { player: "PixelSniper", ks: 19, date: new Date().toISOString() },
  { player: "PixelSniper", ks: 30, date: new Date(Date.now() - 86400000 * 2).toISOString() },
  { player: "VoidWalker", ks: 2, date: new Date().toISOString() },
  { player: "NullPointer", ks: 0, date: new Date().toISOString() },
  { player: "NullPointer", ks: 50, date: new Date(Date.now() - 86400000 * 40).toISOString() },
];

export const fetchAndParseData = async (): Promise<RawDataRow[]> => {
  try {
    const response = await fetch(SHEET_URL);
    if (!response.ok) {
      throw new Error('Network response was not ok');
    }
    const text = await response.text();
    return parseCSV(text);
  } catch (error) {
    console.warn("Failed to fetch live data, using fallback/mock data.", error);
    // Return mock data for demonstration if live fetch fails (likely due to CORS on local dev)
    return MOCK_DATA;
  }
};

const parseCSV = (csvText: string): RawDataRow[] => {
  const lines = csvText.split('\n').filter(line => line.trim() !== '');
  if (lines.length < 2) return [];

  // Simple parser assuming headers might exist but mapping mostly by index or flexible matching
  // Expected structure assumption: Player Name, KS, Date (optional)
  // We'll skip the header row
  const data: RawDataRow[] = [];

  for (let i = 1; i < lines.length; i++) {
    const cols = lines[i].split(',').map(c => c.trim().replace(/^"|"$/g, ''));

    // Safety check for empty rows
    if (cols.length < 2) continue;

    const name = cols[0];
    const ks = parseInt(cols[1], 10) || 0;

    // Try to parse date, default to today if missing or invalid
    let dateStr = cols[2];
    let dateObj = new Date();
    if (dateStr) {
      const parsed = new Date(dateStr);
      if (!isNaN(parsed.getTime())) {
        dateObj = parsed;
      }
    }

    data.push({
      player: name,
      ks: ks,
      date: dateObj.toISOString()
    });
  }

  return data;
};

export const aggregateData = (rawData: RawDataRow[], frame: TimeFrame): RankedPlayer[] => {
  const now = new Date();
  const playerMap = new Map<string, { totalKS: number; games: number; }>();

  // Filter Data
  const filteredData = rawData.filter(row => {
    const rowDate = new Date(row.date);

    switch (frame) {
      case TimeFrame.DAILY:
        return rowDate.toDateString() === now.toDateString();
      case TimeFrame.WEEKLY:
        const oneWeekAgo = new Date();
        oneWeekAgo.setDate(now.getDate() - 7);
        return rowDate >= oneWeekAgo;
      case TimeFrame.MONTHLY:
        return rowDate.getMonth() === now.getMonth() && rowDate.getFullYear() === now.getFullYear();
      case TimeFrame.ALL_TIME:
      default:
        return true;
    }
  });

  // Aggregate
  filteredData.forEach(row => {
    const current = playerMap.get(row.player) || { totalKS: 0, games: 0 };
    playerMap.set(row.player, {
      totalKS: current.totalKS + row.ks,
      games: current.games + 1
    });
  });

  // Convert to array and sort
  const ranked: RankedPlayer[] = Array.from(playerMap.entries()).map(([name, stats]) => ({
    name,
    totalKS: stats.totalKS,
    gamesPlayed: stats.games,
    averageKS: stats.games > 0 ? parseFloat((stats.totalKS / stats.games).toFixed(1)) : 0,
    rank: 0, // Assigned later
    trend: Math.random() > 0.6 ? 'up' : Math.random() > 0.5 ? 'down' : 'same' // Mock trend logic for visual flair
  }));

  // Sort by Total KS descending
  ranked.sort((a, b) => b.totalKS - a.totalKS);

  // Assign Rank
  return ranked.map((p, index) => ({ ...p, rank: index + 1 }));
};

