import React from 'react';
import { RankedPlayer } from '../types';
import { TrophyIcon } from './NeonIcons';

interface PodiumProps {
  players: RankedPlayer[];
}

const PodiumStep: React.FC<{ player: RankedPlayer; place: 1 | 2 | 3 }> = ({ player, place }) => {
  const isFirst = place === 1;
  const height = isFirst ? 'h-48' : place === 2 ? 'h-36' : 'h-28';

  // Dynamic colors based on rank
  const borderColor = isFirst ? 'border-neon-purple shadow-neon-purple' : place === 2 ? 'border-neon-blue shadow-neon-blue' : 'border-neon-green shadow-neon-green';
  const textColor = isFirst ? 'text-neon-purple' : place === 2 ? 'text-neon-blue' : 'text-neon-green';
  const scale = isFirst ? 'scale-110 z-10' : 'scale-100 z-0';

  return (
    <div className={`flex flex-col items-center justify-end ${scale} transition-transform duration-500`}>
      {/* Avatar/Initial */}
      <div className={`w-16 h-16 rounded-full border-2 ${borderColor} flex items-center justify-center bg-black mb-3 relative overflow-hidden group`}>
         <div className={`absolute inset-0 bg-opacity-20 bg-white group-hover:bg-opacity-30 transition-all`} />
         <span className={`text-xl font-bold ${textColor}`}>{player.name.substring(0, 2).toUpperCase()}</span>
         {isFirst && <div className="absolute -top-6 animate-bounce"><TrophyIcon className="w-6 h-6 text-yellow-400 drop-shadow-md" /></div>}
      </div>

      {/* Name and Score */}
      <div className="text-center mb-2">
        <div className="font-display font-bold text-white tracking-wider text-sm truncate max-w-[100px]">{player.name}</div>
        <div className={`font-mono font-bold text-lg ${textColor}`}>{player.totalKS} KS</div>
      </div>

      {/* Bar */}
      <div className={`w-20 ${height} ${borderColor} bg-opacity-10 bg-gradient-to-t from-gray-900 via-gray-800 to-transparent border-t-4 rounded-t-lg flex items-end justify-center pb-2 backdrop-blur-sm`}>
        <span className="text-4xl font-display font-black text-white opacity-20">{place}</span>
      </div>
    </div>
  );
};

export const Podium: React.FC<PodiumProps> = ({ players }) => {
  if (players.length === 0) return null;

  const first = players[0];
  const second = players.length > 1 ? players[1] : null;
  const third = players.length > 2 ? players[2] : null;

  return (
    <div className="flex justify-center items-end space-x-2 md:space-x-8 mb-10 pt-8 px-4">
      {second && <PodiumStep player={second} place={2} />}
      {first && <PodiumStep player={first} place={1} />}
      {third && <PodiumStep player={third} place={3} />}
    </div>
  );
};

import React from 'react';
import { RankedPlayer } from '../types';
import { TrendDown, TrendSame, TrendUp } from './NeonIcons';

interface RankingListProps {
