import { RawDataRow, RankedPlayer, TimeFrame } from '../types';

const SHEET_URL = 'https://docs.google.com/spreadsheets/d/e/2PACX-1vQkJhKP1MWxMqBupRr3TmzbsuoZHF2ljzRG1lMCjZ--46ON-vVoPf4mgn5PqjmiWtOpphpmkPYFeYLK/pub?output=csv';

export const fetchAndParseData = async (): Promise<RawDataRow[]> => {
  try {
    // Add cache busting to ensure we get fresh data
    const response = await fetch(`${SHEET_URL}&t=${Date.now()}`);

    if (!response.ok) {
      console.error('Failed to fetch CSV:', response.statusText);
      throw new Error('Network response was not ok');
    }

    const text = await response.text();
    console.log("Raw CSV fetched:", text.substring(0, 200) + "..."); // Log start of CSV for debug
    return parseCSV(text);
  } catch (error) {
    console.error("Error fetching/parsing live data:", error);
    return []; // Return empty to indicate failure rather than showing fake data
  }
};

const parseCSV = (csvText: string): RawDataRow[] => {
  const lines = csvText.split(/\r?\n/).filter(line => line.trim() !== '');
  if (lines.length < 2) return [];

  // Parse Header to find indices
  // We use a regex to split by comma, respecting quotes
  const parseLine = (line: string) => {
    const matches = line.match(/(".*?"|[^",\s]+)(?=\s*,|\s*$)/g) || [];
    // Fallback simple split if regex misses (simple CSVs)
    if (matches.length === 0) return line.split(',').map(s => s.trim());
    return matches.map(m => m.replace(/^"|"$/g, '').trim()); // remove quotes
  };

  // Try to match headers to find column indices
  const headers = parseLine(lines[0]).map(h => h.toLowerCase());
  console.log("Detected headers:", headers);

  // Heuristics for column detection
  let nameIdx = headers.findIndex(h => 
    h.includes('player') || h.includes('nome') || h.includes('nick') || h.includes('jogador') || h.includes('gamertag')
  );

  let ksIdx = headers.findIndex(h => 
    h.includes('ks') || h.includes('kill') || h.includes('score') || h.includes('pontos') || h.includes('abates')
  );

  let dateIdx = headers.findIndex(h => 
    h.includes('date') || h.includes('data') || h.includes('time') || h.includes('carimbo') || h.includes('timestamp')
  );

  // Fallback Logic if headers are not clear
  if (nameIdx === -1 || ksIdx === -1) {
    console.warn("Could not auto-detect columns from headers. Using positional fallback.");
    // If column 0 looks like a timestamp, assume structure: Timestamp | Name | KS
    if (lines[1] && (lines[1].includes('/') || lines[1].includes(':') || !isNaN(Date.parse(lines[1].split(',')[0])))) {
        nameIdx = 1;
        ksIdx = 2;
        dateIdx = 0;
    } else {
        // Assume simple structure: Name | KS | Date?
        nameIdx = 0;
        ksIdx = 1;
        dateIdx = 2;
    }
  }

  const data: RawDataRow[] = [];

  for (let i = 1; i < lines.length; i++) {
    const cols = lines[i].split(',').map(c => c.trim().replace(/^"|"$/g, ''));

    // Safety check
    if (cols.length < 2) continue;

    const name = cols[nameIdx];
    // Ensure we parse KS as number, handling potential empty strings or bad formats
    const ksString = cols[ksIdx];
    const ks = ksString ? parseInt(ksString.replace(/\D/g, ''), 10) || 0 : 0;

    // Filter out rows with empty names or invalid KS (optional, but keeps data clean)
    if (!name) continue;

    // Date parsing
    let dateObj = new Date();
    if (dateIdx !== -1 && cols[dateIdx]) {
      const parsed = new Date(cols[dateIdx]);
      if (!isNaN(parsed.getTime())) {
        dateObj = parsed;
      }
    }

    data.push({
