const SHEET_URL = 'https://docs.google.com/spreadsheets/d/e/2PACX-1vQkJhKP1MWxMqBupRr3TmzbsuoZHF2ljzRG1lMCjZ--46ON-vVoPf4mgn5PqjmiWtOpphpmkPYFeYLK/pub?output=csv';

export const fetchAndParseData = async (): Promise<RawDataRow[]> => {
  try {
    // Add cache busting to ensure we get fresh data
    const response = await fetch(`${SHEET_URL}&t=${Date.now()}`);

    if (!response.ok) {
      console.error('Failed to fetch CSV:', response.statusText);
      throw new Error('Network response was not ok');
    }

    const text = await response.text();
    // console.log("Raw CSV fetched:", text.substring(0, 200) + "..."); 
    return parseCSV(text);
  } catch (error) {
    console.error("Error fetching/parsing live data:", error);
    return []; 
  }
};

const parseCSV = (csvText: string): RawDataRow[] => {
  const lines = csvText.split(/\r?\n/).filter(line => line.trim() !== '');
  if (lines.length < 2) return [];

  const data: RawDataRow[] = [];

  // Start loop from 1 to skip the header row
  for (let i = 1; i < lines.length; i++) {
    // Regex to split by comma but respect quotes (e.g. "Name, Surname")
    const matches = lines[i].match(/(".*?"|[^",\s]+)(?=\s*,|\s*$)/g) || [];
    let cols = matches.map(m => m.replace(/^"|"$/g, '').trim());

    // Fallback: if regex failed to split correctly (simple CSV structure), use standard split
    if (cols.length === 0) {
        cols = lines[i].split(',').map(c => c.trim());
    }

    // STRICT MAPPING AS REQUESTED:
    // Col A (Index 0): Timestamp / Date
    // Col C (Index 2): Nome do Char (Player Name)

    // Ensure we have at least up to column C
    if (cols.length <= 2) continue;

    const dateStr = cols[0]; // Timestamp
    const name = cols[2];    // Column C - Nome do Char

    // Validation: Name must exist and not be empty
    if (!name) continue;

    // Date Parsing logic
    let dateObj = new Date();
    if (dateStr) {
      // Try standard parsing
      const parsed = new Date(dateStr);

      // Some Google Sheets exports are DD/MM/YYYY, which `new Date()` might misinterpret as MM/DD/YYYY or invalid.
      // This simple block checks if valid; if not, it falls back to "now".
      // For a more robust app, a library like date-fns would be used, but this works for standard ISO or US formats often returned by the web publish link.
      if (!isNaN(parsed.getTime())) {
        dateObj = parsed;
      }
    }

    data.push({
      player: name,
      ks: 1, // Logic change: Each row counts as 1 Kill/Score.
      date: dateObj.toISOString()
    });
  }

  return data;
};

export const aggregateData = (rawData: RawDataRow[], frame: TimeFrame): RankedPlayer[] => {
  const now = new Date();
  const playerMap = new Map<string, { totalKS: number; games: number; }>();

  // Filter Data based on TimeFrame
  const filteredData = rawData.filter(row => {
