        <div className="relative z-10 w-full text-center px-1 mb-2">
            <h3 className={`
              font-display font-bold leading-tight break-words w-full
              ${isFirst ? 'text-lg md:text-xl text-white' : 'text-base md:text-lg text-gray-200'}
