import { RawDataRow, RankedPlayer, TimeFrame } from '../types';

const SHEET_URL = 'https://docs.google.com/spreadsheets/d/e/2PACX-1vQkJhKP1MWxMqBupRr3TmzbsuoZHF2ljzRG1lMCjZ--46ON-vVoPf4mgn5PqjmiWtOpphpmkPYFeYLK/pub?output=csv';

export const fetchAndParseData = async (): Promise<RawDataRow[]> => {
  try {
    const response = await fetch(`${SHEET_URL}&t=${Date.now()}`);

    if (!response.ok) {
      throw new Error('Network response was not ok');
    }

    const text = await response.text();
    return parseCSV(text);
  } catch (error) {
    console.error("Error fetching/parsing live data:", error);
    return []; 
  }
};

const parseCSV = (csvText: string): RawDataRow[] => {
  const lines = csvText.split(/\r?\n/).filter(line => line.trim() !== '');
  if (lines.length < 2) return [];

  const data: RawDataRow[] = [];

  for (let i = 1; i < lines.length; i++) {
    const cols = parseCSVLine(lines[i]);

    // Col A (Index 0): Timestamp / Date
    // Col C (Index 2): Nome do Char (Player Name)
    // We need at least 3 columns to get the name at index 2
    if (cols.length <= 2) continue;

    const dateStr = cols[0];
    const name = cols[2];

    if (!name) continue;

    let dateObj = new Date();

    // Robust Date Parsing
    if (dateStr) {
      // Handle DD/MM/YYYY format common in Brazil/Google Sheets
      const ddmmyyyy = dateStr.match(/^(\d{1,2})\/(\d{1,2})\/(\d{4})/);

      if (ddmmyyyy) {
         // Force structure Year, Month (0-index), Day
         dateObj = new Date(
             parseInt(ddmmyyyy[3]), 
             parseInt(ddmmyyyy[2]) - 1, 
             parseInt(ddmmyyyy[1])
         );

         // If time is present, try to add it, otherwise default to T00:00:00
         if (dateStr.includes(':')) {
            const timePart = dateStr.split(' ')[1];
            if (timePart) {
                const [h, m, s] = timePart.split(':').map(Number);
                dateObj.setHours(h || 0, m || 0, s || 0);
            }
         }
      } else {
         // Fallback to standard parser (ISO or US format)
         const parsed = new Date(dateStr);
         if (!isNaN(parsed.getTime())) {
            dateObj = parsed;
         }
      }
    }

    data.push({
      player: name,
      ks: 1, 
      date: dateObj.toISOString()
    });
  }

  return data;
};

// Helper to parse CSV line correctly handling quotes and commas
// This prevents splitting names with spaces like "Pura Fibra ED" into multiple columns
const parseCSVLine = (text: string): string[] => {
    const cols: string[] = [];
    let current = '';
    let inQuote = false;

    for (let i = 0; i < text.length; i++) {
        const char = text[i];

        if (char === '"') {
            // Check for escaped quote ("")
            if (inQuote && text[i+1] === '"') {
                current += '"';
                i++; // Skip next quote
            } else {
                inQuote = !inQuote;
            }
        } else if (char === ',' && !inQuote) {
            cols.push(current.trim());
            current = '';
        } else {
            current += char;
        }
    }

    // Push the last column
    cols.push(current.trim());
    return cols;
};

export const aggregateData = (
    rawData: RawDataRow[], 
    frame: TimeFrame
): RankedPlayer[] => {
  const now = new Date();

  const playerMap = new Map<string, { totalKS: number; games: number; }>();

  // Filter Data based on TimeFrame
  const filteredData = rawData.filter(row => {
    const rowDate = new Date(row.date);

    switch (frame) {
      case TimeFrame.DAILY:
        // Check if it's the same calendar day (DD/MM/YYYY)
        return rowDate.getDate() === now.getDate() &&
               rowDate.getMonth() === now.getMonth() &&
               rowDate.getFullYear() === now.getFullYear();

      case TimeFrame.WEEKLY:
        // Last 7 Days
        const sevenDaysAgo = new Date();
        sevenDaysAgo.setDate(now.getDate() - 7);
        sevenDaysAgo.setHours(0,0,0,0);
        return rowDate >= sevenDaysAgo;

      case TimeFrame.MONTHLY:
        // Last 30 Days (Rolling Window)
        const thirtyDaysAgo = new Date();
        thirtyDaysAgo.setDate(now.getDate() - 30);
        thirtyDaysAgo.setHours(0,0,0,0);
        return rowDate >= thirtyDaysAgo;

      case TimeFrame.ALL_TIME:
      default:
        return true;
    }
  });

  // Aggregate
  filteredData.forEach(row => {
    const current = playerMap.get(row.player) || { totalKS: 0, games: 0 };
    playerMap.set(row.player, {
      totalKS: current.totalKS + row.ks,
      games: current.games + 1
    });
  });

  // Convert to array
  const ranked: RankedPlayer[] = Array.from(playerMap.entries()).map(([name, stats]) => ({
    name,
    totalKS: stats.totalKS,
    gamesPlayed: stats.games,
    averageKS: 1, 
    rank: 0, 
    trend: 'same' 
  }));

  // Sort by Total KS descending
  ranked.sort((a, b) => b.totalKS - a.totalKS);

  // Assign Rank & Trend
  return ranked.map((p, index) => ({ 
      ...p, 
      rank: index + 1,
      trend: index < 3 ? 'up' : index > 10 ? 'down' : 'same'
  }));
};

