export const getOverviewStats = (rawData: RawDataRow[]): OverviewData => {
    let totalKills = 0;
    const hourlyCounts = new Array(24).fill(0);
    const weeklyCounts = new Array(7).fill(0);
    const dateMap = new Map<string, number>();
    let normalKills = 0;
    let heavyKills = 0;

    rawData.forEach(row => {
        const date = new Date(row.date);

        // Totals
        totalKills += row.ks;
        if (row.ks > 1) heavyKills++; else normalKills++;

        // Hourly (local time)
        const hour = date.getHours();
        if (hour >= 0 && hour < 24) hourlyCounts[hour] += row.ks;

        // Weekly (0 = Sunday)
        const day = date.getDay();
        if (day >= 0 && day < 7) weeklyCounts[day] += row.ks;

        // Daily Trend (YYYY-MM-DD)
        const dateKey = date.toISOString().split('T')[0];
        dateMap.set(dateKey, (dateMap.get(dateKey) || 0) + row.ks);
    });

    // Process Trend (Last 14 days logic or just sort all)
    const sortedDates = Array.from(dateMap.entries())
        .map(([date, count]) => ({ date, count }))
        .sort((a, b) => a.date.localeCompare(b.date));

    // Take last 14 entries for the trend chart
    const recentTrend = sortedDates.slice(-14);

    // Find Busiest Day of Week
    const days = ['Sunday', 'Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday'];
    const maxDayIndex = weeklyCounts.indexOf(Math.max(...weeklyCounts));

    // Calculate Average per day (based on unique dates in dataset)
    const uniqueDays = dateMap.size || 1;
    const avgKills = Math.round(totalKills / uniqueDays);

    return {
        totalKills,
        totalRecords: rawData.length,
        busiestDay: days[maxDayIndex],
        avgKillsPerDay: avgKills,
        hourlyDistribution: hourlyCounts,
        weeklyDistribution: weeklyCounts,
        dailyTrend: recentTrend,
        weightDistribution: { normal: normalKills, heavy: heavyKills }
    };
};

