import { RawDataRow, RankedPlayer, TimeFrame, OverviewData } from '../types';

const SHEET_URL = 'https://docs.google.com/spreadsheets/d/e/2PACX-1vQkJhKP1MWxMqBupRr3TmzbsuoZHF2ljzRG1lMCjZ--46ON-vVoPf4mgn5PqjmiWtOpphpmkPYFeYLK/pub?output=csv';

export const fetchAndParseData = async (): Promise<RawDataRow[]> => {
  try {
    const response = await fetch(`${SHEET_URL}&t=${Date.now()}`);

    if (!response.ok) {
      throw new Error('Network response was not ok');
    }

    const text = await response.text();
    return parseCSV(text);
  } catch (error) {
    console.error("Error fetching/parsing live data:", error);
    return []; 
  }
};

const parseCSV = (csvText: string): RawDataRow[] => {
  const lines = csvText.split(/\r?\n/).filter(line => line.trim() !== '');
  if (lines.length < 2) return [];

  const data: RawDataRow[] = [];

  for (let i = 1; i < lines.length; i++) {
    const cols = parseCSVLine(lines[i]);

    if (cols.length <= 2) continue;

    const dateStr = cols[0];
    const name = cols[2];
    // Column D (Index 3): Rank
    const rank = cols[3] ? cols[3].trim() : 'Unranked';
    // Column F (Index 5): Respawn
    const respawn = cols[5] ? cols[5].trim() : 'Unknown Area';

    if (!name) continue;

    let dateObj = new Date();

    if (dateStr) {
      const ddmmyyyy = dateStr.match(/^(\d{1,2})\/(\d{1,2})\/(\d{4})/);

      if (ddmmyyyy) {
         dateObj = new Date(
             parseInt(ddmmyyyy[3]), 
             parseInt(ddmmyyyy[2]) - 1, 
             parseInt(ddmmyyyy[1])
         );

         if (dateStr.includes(':')) {
            const timePart = dateStr.split(' ')[1];
            if (timePart) {
                const [h, m, s] = timePart.split(':').map(Number);
                dateObj.setHours(h || 0, m || 0, s || 0);
            }
         }
      } else {
         const parsed = new Date(dateStr);
         if (!isNaN(parsed.getTime())) {
            dateObj = parsed;
         }
      }
    }

    let points = 1;
    if (cols.length > 10) {
        const weightVal = cols[10].trim().toLowerCase();
        if (weightVal === 'peso 02') {
            points = 2;
        }
    }

    data.push({
      player: name,
      ks: points, 
      date: dateObj.toISOString(),
      playerRank: rank || 'Unranked',
      respawn: respawn || 'Unknown Area'
    });
  }

  return data;
};

const parseCSVLine = (text: string): string[] => {
    const cols: string[] = [];
    let current = '';
    let inQuote = false;

    for (let i = 0; i < text.length; i++) {
        const char = text[i];

        if (char === '"') {
            if (inQuote && text[i+1] === '"') {
                current += '"';
                i++;
            } else {
                inQuote = !inQuote;
            }
        } else if (char === ',' && !inQuote) {
            cols.push(current.trim());
            current = '';
        } else {
            current += char;
        }
    }
    cols.push(current.trim());
    return cols;
};

export const getOverviewStats = (rawData: RawDataRow[]): OverviewData => {
    let totalKills = 0;
    const hourlyCounts = new Array(24).fill(0);
    const weeklyCounts = new Array(7).fill(0);
    const dateMap = new Map<string, number>();
    const rankMap = new Map<string, number>();
    const respawnMap = new Map<string, number>();
    let normalKills = 0;
    let heavyKills = 0;

    rawData.forEach(row => {
        const date = new Date(row.date);

        // Totals
        totalKills += row.ks;
        if (row.ks > 1) heavyKills++; else normalKills++;

        // Hourly (local time)
        const hour = date.getHours();
        if (hour >= 0 && hour < 24) hourlyCounts[hour] += row.ks;

        // Weekly (0 = Sunday)
        const day = date.getDay();
        if (day >= 0 && day < 7) weeklyCounts[day] += row.ks;

        // Daily Trend (YYYY-MM-DD)
        const dateKey = date.toISOString().split('T')[0];
        dateMap.set(dateKey, (dateMap.get(dateKey) || 0) + row.ks);

        // Rank Distribution
        const r = row.playerRank;
        rankMap.set(r, (rankMap.get(r) || 0) + row.ks);

        // Respawn Distribution
        const loc = row.respawn;
        respawnMap.set(loc, (respawnMap.get(loc) || 0) + row.ks);
    });

    // Process Trend (Last 14 days logic or just sort all)
    const sortedDates = Array.from(dateMap.entries())
        .map(([date, count]) => ({ date, count }))
        .sort((a, b) => a.date.localeCompare(b.date));

    // Take last 14 entries for the trend chart
    const recentTrend = sortedDates.slice(-14);

    // Process Ranks (Sort by count descending)
    const killsByRank = Array.from(rankMap.entries())
        .map(([rank, count]) => ({ rank, count }))
        .sort((a, b) => b.count - a.count);

    // Process Respawns (Top 5)
    const topRespawns = Array.from(respawnMap.entries())
        .map(([name, count]) => ({ name, count }))
        .sort((a, b) => b.count - a.count)
        .slice(0, 5);

    // Find Busiest Day of Week
    const days = ['Sunday', 'Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday'];
    const maxDayIndex = weeklyCounts.indexOf(Math.max(...weeklyCounts));

    // Calculate Average per day (based on unique dates in dataset)
    const uniqueDays = dateMap.size || 1;
    const avgKills = Math.round(totalKills / uniqueDays);

    return {
        totalKills,
        totalRecords: rawData.length,
        busiestDay: days[maxDayIndex],
        avgKillsPerDay: avgKills,
        hourlyDistribution: hourlyCounts,
        weeklyDistribution: weeklyCounts,
        dailyTrend: recentTrend,
        weightDistribution: { normal: normalKills, heavy: heavyKills },
        killsByRank,
        topRespawns
    };
};

export const aggregateData = (
    rawData: RawDataRow[], 
    frame: TimeFrame
): RankedPlayer[] => {
  const now = new Date();

  if (frame === TimeFrame.OVERVIEW) return [];

  const playerMap = new Map<string, { totalKS: number; games: number; }>();

  const filteredData = rawData.filter(row => {
    const rowDate = new Date(row.date);

    switch (frame) {
      case TimeFrame.DAILY:
        return rowDate.getDate() === now.getDate() &&
               rowDate.getMonth() === now.getMonth() &&
               rowDate.getFullYear() === now.getFullYear();

      case TimeFrame.WEEKLY:
        const sevenDaysAgo = new Date();
        sevenDaysAgo.setDate(now.getDate() - 7);
        sevenDaysAgo.setHours(0,0,0,0);
        return rowDate >= sevenDaysAgo;

      case TimeFrame.MONTHLY:
        const thirtyDaysAgo = new Date();
        thirtyDaysAgo.setDate(now.getDate() - 30);
        thirtyDaysAgo.setHours(0,0,0,0);
        return rowDate >= thirtyDaysAgo;

      case TimeFrame.ALL_TIME:
      default:
        return true;
    }
  });

  filteredData.forEach(row => {
    const current = playerMap.get(row.player) || { totalKS: 0, games: 0 };
    playerMap.set(row.player, {
      totalKS: current.totalKS + row.ks,
      games: current.games + 1
    });
  });

  const ranked: RankedPlayer[] = Array.from(playerMap.entries()).map(([name, stats]) => ({
    name,
    totalKS: stats.totalKS,
    gamesPlayed: stats.games,
    averageKS: 1, 
    rank: 0, 
    trend: 'same' 
  }));

  ranked.sort((a, b) => b.totalKS - a.totalKS);

  return ranked.map((p, index) => ({ 
      ...p, 
      rank: index + 1,
      trend: index < 3 ? 'up' : index > 10 ? 'down' : 'same'
  }));
};

