export enum TimeFrame {
  OVERVIEW = 'OVERVIEW',
  DAILY = 'DAILY',
  WEEKLY = 'WEEKLY',
  MONTHLY = 'MONTHLY',
  ALL_TIME = 'ALL_TIME'
}

export interface RawDataRow {
  player: string;
  ks: number;
  date: string; // ISO string or simple date string
