    // Better strategy: Use current date so it shows up in "Today" or "Overview" at least.
    if (!dateObj) {
        // console.warn(`Failed to parse date: ${dateStr}`);
        dateObj = new Date(); 
    }

    let points = 1;
    // Check for "Peso 02" in later columns (around index 10)
    // We check a range because sometimes columns shift slightly
    if (cols.length > 8) {
        // Look in columns 8 through 12 for weight info
        for (let j = 8; j < Math.min(cols.length, 14); j++) {
            if (cols[j] && cols[j].trim().toLowerCase() === 'peso 02') {
                points = 2;
