const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<TimeFrame>(TimeFrame.OVERVIEW);
  const [rawData, setRawData] = useState<RawDataRow[]>([]);
  const [rankedPlayers, setRankedPlayers] = useState<RankedPlayer[]>([]);
  const [overviewData, setOverviewData] = useState<OverviewData | null>(null);
  const [loading, setLoading] = useState(true);
  const [isRefreshing, setIsRefreshing] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Reusable data fetch function
  const loadData = useCallback(async (isManualRefresh = false) => {
    if (isManualRefresh) setIsRefreshing(true);
    else setLoading(true);

    setError(null);
    try {
      const data = await fetchAndParseData();

      if (data.length === 0) {
        setError("Unable to load data. The spreadsheet might be empty, formatted incorrectly, or inaccessible.");
      } else {
        setRawData(data);
        setOverviewData(getOverviewStats(data));

        // If we are not in overview, update the current tab's ranking immediately
        if (activeTab !== TimeFrame.OVERVIEW) {
          const ranked = aggregateData(data, activeTab);
          setRankedPlayers(ranked);
        }
      }
    } catch (err) {
      setError("A connection error occurred while fetching combat data.");
    } finally {
      setLoading(false);
      setIsRefreshing(false);
    }
  }, [activeTab]);

  // Initial Data Fetch
  useEffect(() => {
    loadData();
  }, []); // Only run once on mount

  // Update rankings when tab changes (based on existing rawData)
  useEffect(() => {
    if (rawData.length > 0 && activeTab !== TimeFrame.OVERVIEW) {
      const ranked = aggregateData(rawData, activeTab);
      setRankedPlayers(ranked);
    }
  }, [activeTab, rawData]);

  const tabs = [
    { id: TimeFrame.OVERVIEW, label: 'Overview', subLabel: 'System Stats' },
    { id: TimeFrame.DAILY, label: 'Today', subLabel: 'Last 24h' },
    { id: TimeFrame.WEEKLY, label: 'Weekly', subLabel: 'Last 7 Days' },
    { id: TimeFrame.MONTHLY, label: 'Monthly', subLabel: 'Last 30 Days' },
    { id: TimeFrame.ALL_TIME, label: 'Legends', subLabel: 'All Time' },
  ];

  return (
    <div className="min-h-screen bg-neon-dark text-white selection:bg-neon-blue selection:text-black font-sans overflow-x-hidden">

      {/* MJR Symbol - Top Right */}
      <div className="fixed top-6 right-6 z-50 flex flex-col items-center justify-center w-14 h-14 bg-black/40 border-2 border-neon-blue rounded-xl shadow-neon-blue pointer-events-none">
        <svg 
          xmlns="http://www.w3.org/2000/svg" 
          fill="none" 
          viewBox="0 0 24 24" 
          strokeWidth={4} 
          stroke="currentColor" 
          className="w-6 h-6 text-neon-blue drop-shadow-[0_0_5px_#00f3ff]"
        >
          <path strokeLinecap="round" strokeLinejoin="round" d="M4.5 10.5L12 3m0 0l7.5 7.5M12 3v18" />
        </svg>
        <span className="font-display font-black text-[10px] text-neon-blue mt-0.5 tracking-tighter drop-shadow-[0_0_3px_#00f3ff]">
          MJR
        </span>
      </div>

      {/* Background Decor */}
      <div className="fixed top-0 left-0 w-full h-full pointer-events-none overflow-hidden z-0">
         <div className="absolute -top-20 -left-20 w-96 h-96 bg-neon-purple opacity-10 blur-[100px] rounded-full" />
         <div className="absolute top-1/2 right-0 w-80 h-80 bg-neon-blue opacity-10 blur-[120px] rounded-full" />
      </div>

      <div className="relative z-10 container mx-auto px-4 py-8">

        {/* Header */}
        <header className="flex flex-col items-center mb-10">
          <div className="relative mb-2">
            <h1 className="text-4xl md:text-6xl font-display font-black tracking-tighter text-transparent bg-clip-text bg-gradient-to-r from-neon-blue via-white to-neon-purple drop-shadow-lg text-center">
              MissclicKS
            </h1>
            <div className="absolute -inset-1 blur-lg bg-neon-blue opacity-20 animate-pulse"></div>
          </div>
          <p className="text-neon-blue tracking-widest text-xs uppercase opacity-80 flex items-center gap-2">
            <TargetIcon className="w-4 h-4" /> Kill Score Tracker
          </p>
        </header>

        {/* Navigation Tabs */}
        <div className="flex justify-center mb-10">
            <div className="flex flex-wrap justify-center p-1 bg-neon-surface border border-gray-800 rounded-xl gap-1">
                {tabs.map((tab) => (
                <button
                    key={tab.id}
                    onClick={() => setActiveTab(tab.id)}
                    className={`
                    relative px-4 md:px-6 py-2 rounded-lg transition-all duration-300 flex flex-col items-center justify-center min-w-[100px]
                    ${activeTab === tab.id 
                        ? (tab.id === TimeFrame.ALL_TIME ? 'text-black bg-gradient-to-r from-yellow-400 to-yellow-600 shadow-[0_0_15px_rgba(234,179,8,0.6)]' : 'text-black bg-neon-blue shadow-[0_0_15px_rgba(0,243,255,0.5)]') 
                        : 'text-gray-400 hover:text-white hover:bg-white/5'}
                    `}
                >
                    <span className="font-display font-bold text-sm uppercase">{tab.label}</span>
                    <span className={`text-[10px] ${activeTab === tab.id ? 'text-gray-900 font-bold' : 'text-gray-600'}`}>{tab.subLabel}</span>
                </button>
                ))}
            </div>
        </div>

        {/* Content Area */}
        {loading ? (
          <div className="flex justify-center items-center h-64">
            <div className="w-12 h-12 border-4 border-neon-blue border-t-transparent rounded-full animate-spin"></div>
          </div>
        ) : error ? (
            <div className="text-center p-8 bg-neon-surface border border-red-500/50 rounded-xl max-w-lg mx-auto">
                <p className="text-red-400 font-bold mb-2">System Error</p>
                <p className="text-gray-400 text-sm mb-4">{error}</p>
                <p className="text-xs text-gray-500">Ensure the Google Sheet is "Published to Web" as CSV.</p>
                <button 
                    onClick={() => loadData()}
                    className="mt-4 px-6 py-2 bg-red-500/20 hover:bg-red-500/40 text-red-300 rounded border border-red-500/50 transition-colors"
                >
                    Retry Connection
                </button>
            </div>
        ) : (
          <main className="animate-fade-in">
            {activeTab === TimeFrame.OVERVIEW ? (
                 overviewData && <Overview data={overviewData} />
            ) : activeTab === TimeFrame.ALL_TIME ? (
                 <LegendsView players={rankedPlayers} />
            ) : (
                <>
                    <div className="mb-4 text-center">
                    <h2 className="text-2xl font-display text-white mb-1">
                        {tabs.find(t => t.id === activeTab)?.label} Ranking
                    </h2>
                    <p className="text-gray-500 text-sm">
                        {activeTab === TimeFrame.DAILY && "KS confirmed today."}
                        {activeTab === TimeFrame.WEEKLY && "Performance over the last 7 days."}
                        {activeTab === TimeFrame.MONTHLY && "Performance over the last 30 days."}
                    </p>
                    </div>

                    {/* Empty State for Ranking */}
                    {rankedPlayers.length === 0 ? (
                        <div className="text-center py-20 opacity-50 bg-neon-surface/30 rounded-xl border border-dashed border-gray-800 mx-auto max-w-2xl mt-8">
                            <p className="font-display text-xl text-gray-400">No data found for this period.</p>
                            <p className="text-sm text-gray-600 mt-2">Start scoring KS to appear here!</p>
                        </div>
                    ) : (
                        <>
                            {/* Standard Neon Podium */}
                            <Podium players={rankedPlayers} />

                            {/* Standard Ranking List */}
                            <RankingList players={rankedPlayers} />
                        </>
                    )}
                </>
            )}
          </main>
        )}
      </div>

      {/* Floating Action Button (Internal Refresh) */}
      <button 
        onClick={() => loadData(true)}
        disabled={isRefreshing || loading}
        className={`fixed bottom-6 right-6 w-14 h-14 bg-neon-surface border border-neon-purple rounded-full flex items-center justify-center text-neon-purple hover:bg-neon-purple hover:text-white transition-all shadow-lg hover:shadow-neon-purple z-50 group ${isRefreshing ? 'cursor-not-allowed opacity-80' : ''}`}
        aria-label="Refresh Data"
      >
        <svg 
          xmlns="http://www.w3.org/2000/svg" 
          fill="none" 
          viewBox="0 0 24 24" 
          strokeWidth={2} 
          stroke="currentColor" 
          className={`w-7 h-7 ${isRefreshing ? 'animate-spin' : 'group-hover:rotate-180 transition-transform duration-700'}`}
        >
          <path strokeLinecap="round" strokeLinejoin="round" d="M16.023 9.348h4.992v-.001M2.985 19.644v-4.992m0 0h4.992m-4.993 0l3.181 3.183a8.25 8.25 0 0013.803-3.7M4.031 9.865a8.25 8.25 0 0113.803-3.7l3.181 3.182m0-4.991v4.99" />
        </svg>

        {/* Tooltip on hover */}
        {!isRefreshing && (
          <span className="absolute right-full mr-3 px-2 py-1 bg-black text-white text-[10px] font-bold uppercase tracking-widest rounded border border-gray-800 opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none whitespace-nowrap">
            Update Feed
          </span>
        )}
      </button>

      <footer className="text-center py-6 text-gray-600 text-xs">
         <p>MissclicKS &copy; {new Date().getFullYear()} // System Online</p>
      </footer>
    </div>
  );
};

export default App;

export enum TimeFrame {
  OVERVIEW = 'OVERVIEW',
  DAILY = 'DAILY',
  WEEKLY = 'WEEKLY',
  MONTHLY = 'MONTHLY',
  ALL_TIME = 'ALL_TIME',
  SCANNER = 'SCANNER' // New tab for AI Validation
}

export interface RawDataRow {
  player: string;
  ks: number;
  date: string; 
  playerRank: string; 
  respawn: string; 
}

export interface RankedPlayer {
  rank: number;
  name: string;
  totalKS: number;
  gamesPlayed: number;
  averageKS: number;
  trend: 'up' | 'down' | 'same'; 
}

export interface ValidationResult {
  success: boolean;
  huntAnalyser: boolean;
  stamina: boolean;
  vipList: boolean;
  personalRecord: boolean;
  details: string;
}

export interface OverviewData {
  totalKills: number;
  totalRecords: number;
  busiestDay: string;
  avgKillsPerDay: number;
  hourlyDistribution: number[]; 
  weeklyDistribution: number[]; 
  dailyTrend: { date: string; count: number }[]; 
  weightDistribution: { normal: number; heavy: number };
  killsByRank: { rank: string; count: number }[]; 
  topRespawns: { name: string; count: number }[]; 
  recentActivity: RawDataRow[]; 
  dominationStats: { name: string; percentage: number; count: number }[]; 
}

export interface RankingData {
  timeFrame: TimeFrame;
  lastUpdated: string;
  players: RankedPlayer[];
}

import React, { useState, useRef } from 'react';
import { GoogleGenAI } from "@google/genai";
import { ValidationResult } from '../types';

export const EyeMissclick: React.FC = () => {
  const [image, setImage] = useState<string | null>(null);
  const [isScanning, setIsScanning] = useState(false);
  const [result, setResult] = useState<ValidationResult | null>(null);
  const [error, setError] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setImage(reader.result as string);
        setResult(null);
        setError(null);
      };
      reader.readAsDataURL(file);
    }
  };

  const scanImage = async () => {
    if (!image) return;

    setIsScanning(true);
    setError(null);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const base64Data = image.split(',')[1];

      const prompt = `
        Analise esta imagem do jogo Tibia como o "EyeMissclick", um validador de protocolos de KS.
        Siga rigorosamente estas regras:
        1. Hunt Analyser: A janela deve estar aberta com tempo de sessão e criaturas mortas visíveis.
        2. Stamina: A janela ou barra de Stamina deve estar visível.
        3. VipList: A janela VipList deve estar aberta.
        4. Pessoal e Intransferível: Procure por textos como "ks com [nome]", "ajuda de [nome]" ou qualquer marcação que indique que o KS não foi solo. Isso é proibido.

        Responda EXATAMENTE neste formato (sem markdown ou blocos de código):
        HUNT: [OK ou FALHA]
        STAMINA: [OK ou FALHA]
        VIP: [OK ou FALHA]
        SOLO: [OK ou FALHA]
        RESUMO: [Um breve comentário técnico sobre a print]
      `;

      const response = await ai.models.generateContent({
        model: 'gemini-2.5-flash-image',
        contents: {
          parts: [
            { inlineData: { data: base64Data, mimeType: 'image/jpeg' } },
            { text: prompt }
          ]
        }
      });

      const text = response.text || "";
      console.log("AI Response:", text);

      // Parse the response
      const hunt = text.includes('HUNT: OK');
      const stamina = text.includes('STAMINA: OK');
      const vip = text.includes('VIP: OK');
      const solo = text.includes('SOLO: OK');
      const detailsMatch = text.match(/RESUMO: (.*)/);
      const details = detailsMatch ? detailsMatch[1] : "Análise concluída.";

      setResult({
        success: hunt && stamina && vip && solo,
        huntAnalyser: hunt,
        stamina: stamina,
        vipList: vip,
        personalRecord: solo,
        details: details
      });

    } catch (err) {
      console.error(err);
      setError("Falha na conexão com o sistema de visão neural.");
    } finally {
      setIsScanning(false);
    }
  };

  return (
    <div className="max-w-4xl mx-auto px-4 py-8 animate-fade-in">
      <div className="text-center mb-10">
        <h2 className="text-4xl font-display font-black text-transparent bg-clip-text bg-gradient-to-r from-neon-blue to-neon-purple uppercase">
          EyeMissclick
        </h2>
        <p className="text-gray-500 text-xs tracking-[0.3em] uppercase mt-2">Protocol Validation AI</p>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">

        {/* Upload Area */}
        <div className="space-y-4">
          <div 
            onClick={() => fileInputRef.current?.click()}
            className={`
              relative aspect-video rounded-2xl border-2 border-dashed transition-all duration-500 cursor-pointer overflow-hidden
              ${image ? 'border-neon-blue' : 'border-gray-800 hover:border-neon-purple bg-white/5'}
            `}
          >
            {image ? (
              <>
                <img src={image} alt="Preview" className="w-full h-full object-cover opacity-60" />
                {isScanning && (
                  <div className="absolute inset-0 bg-gradient-to-b from-transparent via-neon-blue/40 to-transparent h-12 w-full animate-scan-line pointer-events-none" />
                )}
                <div className="absolute inset-0 flex items-center justify-center bg-black/40 opacity-0 hover:opacity-100 transition-opacity">
                  <span className="text-white font-bold text-sm">Trocar Imagem</span>
                </div>
              </>
            ) : (
              <div className="absolute inset-0 flex flex-col items-center justify-center gap-3">
                <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-10 h-10 text-gray-600">
                  <path strokeLinecap="round" strokeLinejoin="round" d="M2.25 15.75l5.159-5.159a2.25 2.25 0 013.182 0l5.159 5.159m-1.5-1.5l1.409-1.409a2.25 2.25 0 013.182 0l2.909 2.909m-18 3.75h16.5a1.5 1.5 0 001.5-1.5V6a1.5 1.5 0 00-1.5-1.5H3.75A1.5 1.5 0 002.25 6v12a1.5 1.5 0 001.5 1.5zm10.5-11.25h.008v.008h-.008V8.25zm.375 0a.375.375 0 11-.75 0 .375.375 0 01.75 0z" />
                </svg>
                <p className="text-gray-500 font-display text-[10px] tracking-widest uppercase">Clique para Upload da Print</p>
              </div>
            )}
            <input 
              type="file" 
              ref={fileInputRef} 
              className="hidden" 
              accept="image/*" 
              onChange={handleFileChange} 
            />
          </div>

          <button
            onClick={scanImage}
            disabled={!image || isScanning}
            className={`
              w-full py-4 rounded-xl font-display font-bold tracking-[0.2em] uppercase transition-all
              ${!image || isScanning 
                ? 'bg-gray-800 text-gray-600 cursor-not-allowed' 
                : 'bg-neon-blue text-black shadow-neon-blue hover:scale-[1.02]'}
            `}
          >
            {isScanning ? 'Analisando Pixels...' : 'Iniciar Escaneamento'}
          </button>
        </div>

        {/* Results Area */}
        <div className="bg-neon-surface border border-gray-800 rounded-2xl p-6 flex flex-col">
          <h3 className="text-white font-display text-sm mb-6 flex items-center gap-2">
            <span className="w-2 h-2 bg-neon-purple rounded-full"></span>
            Relatório de Vistoria
          </h3>

          {!result && !error && (
            <div className="flex-1 flex flex-col items-center justify-center text-center opacity-30">
              <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1} stroke="currentColor" className="w-16 h-16 mb-2">
                <path strokeLinecap="round" strokeLinejoin="round" d="M9 12.75l3 3m0 0l3-3m-3 3v-7.5M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
              </svg>
              <p className="text-xs uppercase tracking-widest">Aguardando dados de entrada...</p>
            </div>
          )}

          {error && (
            <div className="p-4 bg-red-500/10 border border-red-500/50 rounded-lg text-red-400 text-xs text-center">
              {error}
            </div>
          )}

          {result && (
            <div className="space-y-4 animate-fade-in">
              <CheckItem label="Hunt Analyser" passed={result.huntAnalyser} />
              <CheckItem label="Stamina" passed={result.stamina} />
              <CheckItem label="VipList" passed={result.vipList} />
              <CheckItem label="Registro Solo (2.2)" passed={result.personalRecord} />

              <div className="mt-6 p-4 bg-black/40 rounded-xl border border-gray-800">
                <span className="text-[10px] text-gray-500 uppercase block mb-1">Parecer da IA:</span>
                <p className="text-gray-300 text-sm leading-relaxed">{result.details}</p>
              </div>

              <div className={`
                mt-4 py-3 rounded-lg text-center font-display text-xs font-bold uppercase tracking-[0.2em]
                ${result.success ? 'bg-neon-green/20 text-neon-green border border-neon-green/50' : 'bg-red-500/20 text-red-400 border border-red-500/50'}
              `}>
                {result.success ? '✓ Protocolo Aprovado' : '✗ Protocolo Inválido'}
              </div>
            </div>
          )}
        </div>
      </div>

      <div className="mt-12 text-[10px] text-gray-600 leading-loose border-t border-gray-900 pt-6">
        <p className="font-bold text-gray-500 mb-2 uppercase tracking-widest">Lembretes do Procedimento:</p>
        <ul className="grid grid-cols-1 md:grid-cols-2 gap-x-8 gap-y-1">
          <li>• Enviar print do início e do fim da sessão (2.1)</li>
          <li>• Proibido marcar outros players na print (2.2)</li>
          <li>• Hunt Analyser deve estar TOTALMENTE aberto (2.3)</li>
          <li>• Stamina e VipList devem estar abertas (2.3)</li>
          <li>• Falhas resultam em KS desconsiderado (2.5)</li>
        </ul>
      </div>
    </div>
  );
};

const CheckItem: React.FC<{ label: string; passed: boolean }> = ({ label, passed }) => (
  <div className="flex items-center justify-between p-3 bg-black/20 rounded-lg border border-gray-800/50">
    <span className="text-gray-400 text-xs uppercase tracking-wider">{label}</span>
    <span className={`font-bold text-xs ${passed ? 'text-neon-green' : 'text-red-500'}`}>
      {passed ? 'DETECTADO' : 'AUSENTE'}
    </span>
  </div>
);

import React, { useEffect, useState, useCallback } from 'react';
import { TargetIcon } from './components/NeonIcons';
import { Podium } from './components/Podium';
import { RankingList } from './components/RankingList';
import { Overview } from './components/Overview';
import { LegendsView } from './components/LegendsView'; 
import { EyeMissclick } from './components/EyeMissclick'; // New import
import { aggregateData, fetchAndParseData, getOverviewStats } from './services/csvService';
import { RankedPlayer, RawDataRow, TimeFrame, OverviewData } from './types';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<TimeFrame>(TimeFrame.OVERVIEW);
  const [rawData, setRawData] = useState<RawDataRow[]>([]);
  const [rankedPlayers, setRankedPlayers] = useState<RankedPlayer[]>([]);
  const [overviewData, setOverviewData] = useState<OverviewData | null>(null);
  const [loading, setLoading] = useState(true);
  const [isRefreshing, setIsRefreshing] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Reusable data fetch function
  const loadData = useCallback(async (isManualRefresh = false) => {
    if (isManualRefresh) setIsRefreshing(true);
    else setLoading(true);

    setError(null);
    try {
      const data = await fetchAndParseData();

      if (data.length === 0) {
        setError("Unable to load data. The spreadsheet might be empty, formatted incorrectly, or inaccessible.");
      } else {
        setRawData(data);
        setOverviewData(getOverviewStats(data));

        // If we are not in overview/scanner, update the current tab's ranking immediately
        if (activeTab !== TimeFrame.OVERVIEW && activeTab !== TimeFrame.SCANNER) {
          const ranked = aggregateData(data, activeTab);
          setRankedPlayers(ranked);
        }
      }
    } catch (err) {
      setError("A connection error occurred while fetching combat data.");
    } finally {
      setLoading(false);
      setIsRefreshing(false);
    }
  }, [activeTab]);

  // Initial Data Fetch
  useEffect(() => {
    loadData();
  }, []); 

  // Update rankings when tab changes (based on existing rawData)
  useEffect(() => {
    if (rawData.length > 0 && activeTab !== TimeFrame.OVERVIEW && activeTab !== TimeFrame.SCANNER) {
      const ranked = aggregateData(rawData, activeTab);
      setRankedPlayers(ranked);
    }
  }, [activeTab, rawData]);

  const tabs = [
    { id: TimeFrame.OVERVIEW, label: 'Overview', subLabel: 'System Stats' },
    { id: TimeFrame.DAILY, label: 'Today', subLabel: 'Last 24h' },
    { id: TimeFrame.WEEKLY, label: 'Weekly', subLabel: 'Last 7 Days' },
    { id: TimeFrame.MONTHLY, label: 'Monthly', subLabel: 'Last 30 Days' },
    { id: TimeFrame.ALL_TIME, label: 'Legends', subLabel: 'All Time' },
    { id: TimeFrame.SCANNER, label: 'Scanner', subLabel: 'AI Validation' }, // New Tab
  ];

  return (
    <div className="min-h-screen bg-neon-dark text-white selection:bg-neon-blue selection:text-black font-sans overflow-x-hidden">

      {/* MJR Symbol - Top Right */}
      <div className="fixed top-6 right-6 z-50 flex flex-col items-center justify-center w-14 h-14 bg-black/40 border-2 border-neon-blue rounded-xl shadow-neon-blue pointer-events-none">
        <svg 
          xmlns="http://www.w3.org/2000/svg" 
          fill="none" 
          viewBox="0 0 24 24" 
          strokeWidth={4} 
          stroke="currentColor" 
          className="w-6 h-6 text-neon-blue drop-shadow-[0_0_5px_#00f3ff]"
        >
          <path strokeLinecap="round" strokeLinejoin="round" d="M4.5 10.5L12 3m0 0l7.5 7.5M12 3v18" />
        </svg>
        <span className="font-display font-black text-[10px] text-neon-blue mt-0.5 tracking-tighter drop-shadow-[0_0_3px_#00f3ff]">
          MJR
        </span>
      </div>

      {/* Background Decor */}
      <div className="fixed top-0 left-0 w-full h-full pointer-events-none overflow-hidden z-0">
         <div className="absolute -top-20 -left-20 w-96 h-96 bg-neon-purple opacity-10 blur-[100px] rounded-full" />
         <div className="absolute top-1/2 right-0 w-80 h-80 bg-neon-blue opacity-10 blur-[120px] rounded-full" />
      </div>

      <div className="relative z-10 container mx-auto px-4 py-8">

        {/* Header */}
        <header className="flex flex-col items-center mb-10">
          <div className="relative mb-2">
            <h1 className="text-4xl md:text-6xl font-display font-black tracking-tighter text-transparent bg-clip-text bg-gradient-to-r from-neon-blue via-white to-neon-purple drop-shadow-lg text-center">
              MissclicKS
            </h1>
            <div className="absolute -inset-1 blur-lg bg-neon-blue opacity-20 animate-pulse"></div>
          </div>
          <p className="text-neon-blue tracking-widest text-xs uppercase opacity-80 flex items-center gap-2">
            <TargetIcon className="w-4 h-4" /> Kill Score Tracker
          </p>
        </header>

        {/* Navigation Tabs */}
        <div className="flex justify-center mb-10">
            <div className="flex flex-wrap justify-center p-1 bg-neon-surface border border-gray-800 rounded-xl gap-1">
                {tabs.map((tab) => (
                <button
                    key={tab.id}
                    onClick={() => setActiveTab(tab.id)}
                    className={`
                    relative px-4 md:px-6 py-2 rounded-lg transition-all duration-300 flex flex-col items-center justify-center min-w-[100px]
                    ${activeTab === tab.id 
                        ? (tab.id === TimeFrame.SCANNER ? 'text-black bg-neon-purple shadow-neon-purple' : (tab.id === TimeFrame.ALL_TIME ? 'text-black bg-gradient-to-r from-yellow-400 to-yellow-600 shadow-[0_0_15px_rgba(234,179,8,0.6)]' : 'text-black bg-neon-blue shadow-[0_0_15px_rgba(0,243,255,0.5)]')) 
                        : 'text-gray-400 hover:text-white hover:bg-white/5'}
                    `}
                >
                    <span className="font-display font-bold text-sm uppercase">{tab.label}</span>
                    <span className={`text-[10px] ${activeTab === tab.id ? 'text-gray-900 font-bold' : 'text-gray-600'}`}>{tab.subLabel}</span>
                </button>
                ))}
            </div>
        </div>

        {/* Content Area */}
        {loading ? (
          <div className="flex justify-center items-center h-64">
            <div className="w-12 h-12 border-4 border-neon-blue border-t-transparent rounded-full animate-spin"></div>
          </div>
        ) : error ? (
            <div className="text-center p-8 bg-neon-surface border border-red-500/50 rounded-xl max-w-lg mx-auto">
                <p className="text-red-400 font-bold mb-2">System Error</p>
                <p className="text-gray-400 text-sm mb-4">{error}</p>
                <button 
                    onClick={() => loadData()}
                    className="mt-4 px-6 py-2 bg-red-500/20 hover:bg-red-500/40 text-red-300 rounded border border-red-500/50 transition-colors"
                >
                    Retry Connection
                </button>
            </div>
        ) : (
          <main className="animate-fade-in">
            {activeTab === TimeFrame.OVERVIEW ? (
                 overviewData && <Overview data={overviewData} />
            ) : activeTab === TimeFrame.ALL_TIME ? (
                 <LegendsView players={rankedPlayers} />
            ) : activeTab === TimeFrame.SCANNER ? (
                 <EyeMissclick />
            ) : (
                <>
                    <div className="mb-4 text-center">
                    <h2 className="text-2xl font-display text-white mb-1">
                        {tabs.find(t => t.id === activeTab)?.label} Ranking
                    </h2>
                    <p className="text-gray-500 text-sm">
                        {activeTab === TimeFrame.DAILY && "KS confirmed today."}
                        {activeTab === TimeFrame.WEEKLY && "Performance over the last 7 days."}
                        {activeTab === TimeFrame.MONTHLY && "Performance over the last 30 days."}
                    </p>
                    </div>

                    {rankedPlayers.length === 0 ? (
                        <div className="text-center py-20 opacity-50 bg-neon-surface/30 rounded-xl border border-dashed border-gray-800 mx-auto max-w-2xl mt-8">
                            <p className="font-display text-xl text-gray-400">No data found for this period.</p>
                            <p className="text-sm text-gray-600 mt-2">Start scoring KS to appear here!</p>
                        </div>
                    ) : (
                        <>
                            <Podium players={rankedPlayers} />
                            <RankingList players={rankedPlayers} />
                        </>
                    )}
                </>
            )}
          </main>
        )}
      </div>

      {/* Floating Action Button */}
      <button 
        onClick={() => loadData(true)}
        disabled={isRefreshing || loading}
        className={`fixed bottom-6 right-6 w-14 h-14 bg-neon-surface border border-neon-purple rounded-full flex items-center justify-center text-neon-purple hover:bg-neon-purple hover:text-white transition-all shadow-lg hover:shadow-neon-purple z-50 group ${isRefreshing ? 'cursor-not-allowed opacity-80' : ''}`}
        aria-label="Refresh Data"
      >
        <svg 
          xmlns="http://www.w3.org/2000/svg" 
          fill="none" 
          viewBox="0 0 24 24" 
          strokeWidth={2} 
          stroke="currentColor" 
          className={`w-7 h-7 ${isRefreshing ? 'animate-spin' : 'group-hover:rotate-180 transition-transform duration-700'}`}
        >
          <path strokeLinecap="round" strokeLinejoin="round" d="M16.023 9.348h4.992v-.001M2.985 19.644v-4.992m0 0h4.992m-4.993 0l3.181 3.183a8.25 8.25 0 0013.803-3.7M4.031 9.865a8.25 8.25 0 0113.803-3.7l3.181 3.182m0-4.991v4.99" />
        </svg>
      </button>

      <footer className="text-center py-6 text-gray-600 text-xs">
         <p>MissclicKS &copy; {new Date().getFullYear()} // System Online</p>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useRef } from 'react';
import { GoogleGenAI } from "@google/genai";
import { ValidationResult } from '../types';

export const EyeMissclick: React.FC = () => {
  const [image, setImage] = useState<string | null>(null);
  const [isScanning, setIsScanning] = useState(false);
  const [result, setResult] = useState<ValidationResult | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [progress, setProgress] = useState(0);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setImage(reader.result as string);
        setResult(null);
        setError(null);
        setProgress(0);
      };
      reader.readAsDataURL(file);
    }
  };

  const scanImage = async () => {
    if (!image) return;

    setIsScanning(true);
    setError(null);
    setProgress(10);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const base64Data = image.split(',')[1];

      setProgress(30);

      const prompt = `
        Aja como o sistema EyeMissclick. Sua missão é validar se esta print de Tibia cumpre os critérios obrigatórios:

        CRITÉRIOS:
        1. HUNT ANALYSER: Janela aberta com "Session" e "Loot/Kills" visíveis.
        2. STAMINA: Barra ou janela de stamina presente.
        3. VIP LIST: Janela VIP List deve estar aberta.
        4. SOLO: Não pode haver menção a "ajuda de", "ks com", "em dupla" ou marcações de outros players invalidando o KS pessoal (Regra 2.2).

        FORMATO DE RESPOSTA (Obrigatório, apenas estas linhas):
        HUNT_STATUS: [OK/ERRO]
        STAMINA_STATUS: [OK/ERRO]
        VIP_STATUS: [OK/ERRO]
        SOLO_STATUS: [OK/ERRO]
        RESUMO: [Breve comentário técnico em português sobre o que encontrou]
      `;

      setProgress(60);

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: {
          parts: [
            { inlineData: { data: base64Data, mimeType: 'image/jpeg' } },
            { text: prompt }
          ]
        }
      });

      setProgress(90);
      const text = response.text || "";
      console.log("EyeMissclick Output:", text);

      // Robust parsing
      const hunt = text.toUpperCase().includes('HUNT_STATUS: OK');
      const stamina = text.toUpperCase().includes('STAMINA_STATUS: OK');
      const vip = text.toUpperCase().includes('VIP_STATUS: OK');
      const solo = text.toUpperCase().includes('SOLO_STATUS: OK');
      const detailsMatch = text.match(/RESUMO: (.*)/i);
      const details = detailsMatch ? detailsMatch[1] : "Análise concluída pelo núcleo EyeMissclick.";

      setResult({
        success: hunt && stamina && vip && solo,
        huntAnalyser: hunt,
        stamina: stamina,
        vipList: vip,
        personalRecord: solo,
        details: details
      });
      setProgress(100);

    } catch (err) {
      console.error(err);
      setError("Erro crítico de conexão neural. Verifique sua rede.");
    } finally {
      setIsScanning(false);
    }
  };

  return (
    <div className="max-w-4xl mx-auto px-4 py-8 animate-fade-in mb-20">
      <div className="text-center mb-10">
        <div className="inline-block relative">
            <h2 className="text-5xl font-display font-black text-white uppercase tracking-tighter">
              Eye<span className="text-neon-blue">Missclick</span>
            </h2>
            <div className="absolute -bottom-2 left-0 w-full h-1 bg-gradient-to-r from-transparent via-neon-blue to-transparent shadow-neon-blue"></div>
        </div>
        <p className="text-gray-500 text-[10px] tracking-[0.5em] uppercase mt-4 opacity-60">Protocolo de Visão Artificial 2.5</p>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 items-start">

        {/* Lado Esquerdo: Upload e Preview */}
        <div className="space-y-6">
          <div 
            onClick={() => !isScanning && fileInputRef.current?.click()}
            className={`
              relative aspect-video rounded-3xl border-2 transition-all duration-700 overflow-hidden group
              ${image ? 'border-neon-blue shadow-neon-blue/20' : 'border-gray-800 hover:border-neon-purple bg-black/40'}
              ${isScanning ? 'cursor-wait' : 'cursor-pointer'}
            `}
          >
            {image ? (
              <>
                <img src={image} alt="Preview" className={`w-full h-full object-cover transition-opacity duration-500 ${isScanning ? 'opacity-40 grayscale' : 'opacity-80'}`} />

                {/* Scanner Laser Animation */}
                {isScanning && (
                  <div className="absolute inset-0 z-20 overflow-hidden">
                    <div className="absolute top-0 left-0 w-full h-1 bg-neon-blue shadow-[0_0_15px_#00f3ff] animate-scan-line"></div>
                    <div className="absolute inset-0 bg-neon-blue/5 animate-pulse"></div>
                  </div>
                )}

                <div className="absolute inset-0 flex items-center justify-center bg-black/60 opacity-0 group-hover:opacity-100 transition-opacity">
                  <span className="bg-white/10 backdrop-blur-md px-4 py-2 rounded-full border border-white/20 text-xs font-bold uppercase tracking-widest text-white">Substituir Print</span>
                </div>
              </>
            ) : (
              <div className="absolute inset-0 flex flex-col items-center justify-center gap-4">
                <div className="w-16 h-16 rounded-full bg-gray-900 border border-gray-800 flex items-center justify-center group-hover:scale-110 group-hover:border-neon-purple transition-all">
                  <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1} stroke="currentColor" className="w-8 h-8 text-gray-500 group-hover:text-neon-purple">
                    <path strokeLinecap="round" strokeLinejoin="round" d="M6.827 6.175A2.31 2.31 0 015.186 7.23c-.38.054-.757.112-1.134.175C2.999 7.58 2.25 8.507 2.25 9.574V18a2.25 2.25 0 002.25 2.25h15a2.25 2.25 0 002.25-2.25V9.574c0-1.067-.75-1.994-1.802-2.169a47.865 47.865 0 00-1.134-.175 2.31 2.31 0 01-1.64-1.055l-.822-1.316a2.192 2.192 0 00-1.736-1.039 48.774 48.774 0 00-5.232 0 2.192 2.192 0 00-1.736 1.039l-.821 1.316z" />
                    <path strokeLinecap="round" strokeLinejoin="round" d="M16.5 12.75a4.5 4.5 0 11-9 0 4.5 4.5 0 019 0zM18.75 10.5h.008v.008h-.008V10.5z" />
                  </svg>
                </div>
                <p className="text-gray-500 font-display text-[10px] tracking-widest uppercase">Solte sua prova aqui</p>
              </div>
            )}
            <input 
              type="file" 
              ref={fileInputRef} 
              className="hidden" 
              accept="image/*" 
              onChange={handleFileChange} 
            />
          </div>

          <button
            onClick={scanImage}
            disabled={!image || isScanning}
            className={`
              w-full py-4 rounded-2xl font-display font-black tracking-[0.3em] uppercase transition-all relative overflow-hidden group
              ${!image || isScanning 
                ? 'bg-gray-900 text-gray-600 cursor-not-allowed border border-gray-800' 
                : 'bg-white text-black hover:bg-neon-blue shadow-xl hover:shadow-neon-blue active:scale-95'}
            `}
          >
            {isScanning ? (
              <span className="flex items-center justify-center gap-3">
                <span className="w-2 h-2 bg-black rounded-full animate-ping"></span>
                Escaneando Biometria de Jogo...
              </span>
            ) : 'Validar Protocolo'}

            {/* Progress Bar Background */}
            {isScanning && (
               <div 
                style={{ width: `${progress}%` }}
                className="absolute bottom-0 left-0 h-1 bg-neon-purple transition-all duration-500 shadow-[0_0_10px_#bc13fe]"
               />
            )}
          </button>
        </div>

        {/* Lado Direito: Resultados */}
        <div className="bg-neon-surface border border-gray-800 rounded-3xl p-8 relative min-h-[400px] flex flex-col">
          <div className="flex items-center justify-between mb-8">
            <h3 className="text-white font-display text-xs tracking-widest uppercase flex items-center gap-3">
              <span className={`w-3 h-3 rounded-full ${isScanning ? 'bg-yellow-500 animate-pulse' : (result ? (result.success ? 'bg-neon-green' : 'bg-red-500') : 'bg-gray-700')}`}></span>
              Status do Diagnóstico
            </h3>
            {result && (
               <span className={`text-[10px] font-bold px-2 py-1 rounded border ${result.success ? 'border-neon-green text-neon-green' : 'border-red-500 text-red-500'}`}>
                 CODE: {result.success ? 'APPROVE_200' : 'DENIED_403'}
               </span>
            )}
          </div>

          {!result && !error && !isScanning && (
            <div className="flex-1 flex flex-col items-center justify-center text-center space-y-4 opacity-20">
              <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={0.5} stroke="currentColor" className="w-24 h-24">
                <path strokeLinecap="round" strokeLinejoin="round" d="M12 21a9.004 9.004 0 008.716-6.747M12 21a9.004 9.004 0 01-8.716-6.747M12 21c2.485 0 4.5-4.03 4.5-9S14.485 3 12 3m0 18c-2.485 0-4.5-4.03-4.5-9S9.515 3 12 3m0 0a8.997 8.997 0 017.843 4.582M12 3a8.997 8.997 0 00-7.843 4.582m15.686 0A11.953 11.953 0 0112 10.5c-2.998 0-5.74-1.1-7.843-2.918m15.686 0A8.959 8.959 0 0121 12c0 .778-.099 1.533-.284 2.253m0 0A17.919 17.919 0 0112 16.5c-3.162 0-6.133-.815-8.716-2.247m0 0A9.015 9.015 0 013 12c0-1.605.42-3.113 1.157-4.418" />
              </svg>
              <p className="text-xs uppercase tracking-[0.3em]">IA em Standby</p>
            </div>
          )}

          {isScanning && (
            <div className="flex-1 flex flex-col items-center justify-center space-y-6">
               <div className="relative w-20 h-20">
                  <div className="absolute inset-0 border-4 border-neon-blue/20 rounded-full"></div>
                  <div className="absolute inset-0 border-4 border-neon-blue border-t-transparent rounded-full animate-spin"></div>
               </div>
               <div className="space-y-2 text-center">
                  <p className="text-neon-blue font-display text-xs animate-pulse">Varredura de Metadados...</p>
                  <p className="text-gray-600 text-[10px] uppercase">Aguardando resposta do servidor neural</p>
               </div>
            </div>
          )}

          {error && (
            <div className="p-6 bg-red-500/10 border border-red-500/30 rounded-2xl text-center space-y-3">
              <p className="text-red-400 text-xs font-bold uppercase">Erro de Processamento</p>
              <p className="text-gray-400 text-[10px]">{error}</p>
            </div>
          )}

          {result && (
            <div className="space-y-4 animate-fade-in flex-1">
              <CheckItem label="Hunt Analyser" passed={result.huntAnalyser} />
              <CheckItem label="Stamina Check" passed={result.stamina} />
              <CheckItem label="VipList Status" passed={result.vipList} />
              <CheckItem label="Protocolo Solo (2.2)" passed={result.personalRecord} />

              <div className="mt-8 p-6 bg-black/40 rounded-2xl border border-gray-800/50 backdrop-blur-sm">
                <span className="text-[9px] text-neon-blue font-bold uppercase block mb-2 tracking-[0.2em]">Observação do EyeMissclick:</span>
                <p className="text-gray-300 text-xs leading-relaxed italic">"{result.details}"</p>
              </div>

              <div className={`
                mt-auto py-4 rounded-xl text-center font-display text-sm font-black uppercase tracking-[0.4em] transition-all
                ${result.success 
                  ? 'bg-neon-green text-black shadow-[0_0_20px_rgba(10,255,10,0.3)]' 
                  : 'bg-red-600 text-white shadow-[0_0_20px_rgba(255,0,0,0.3)]'}
              `}>
                {result.success ? 'Aprovado' : 'Reprovado'}
              </div>
            </div>
          )}
        </div>
      </div>

      <div className="mt-16 grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
         <RuleBox number="2.1" text="Encaminhar duas prints (início e fim) por player." />
         <RuleBox number="2.2" text="Registro pessoal. Não marque outros players." />
         <RuleBox number="2.3" text="Hunt Analyser, Stamina e VipList abertas." />
         <RuleBox number="2.5" text="O não cumprimento invalida o KS." />
      </div>
    </div>
  );
};

const CheckItem: React.FC<{ label: string; passed: boolean }> = ({ label, passed }) => (
  <div className={`flex items-center justify-between p-4 rounded-xl border transition-all duration-300 ${passed ? 'bg-neon-green/5 border-neon-green/20' : 'bg-red-500/5 border-red-500/20'}`}>
    <span className="text-gray-300 text-[10px] font-bold uppercase tracking-wider">{label}</span>
    <div className="flex items-center gap-2">
      <span className={`text-[10px] font-black uppercase ${passed ? 'text-neon-green' : 'text-red-500'}`}>
        {passed ? 'Validado' : 'Inválido'}
      </span>
      <div className={`w-2 h-2 rounded-full ${passed ? 'bg-neon-green shadow-neon-green' : 'bg-red-500 shadow-[0_0_5px_red]'}`}></div>
    </div>
  </div>
);

const RuleBox: React.FC<{ number: string; text: string }> = ({ number, text }) => (
    <div className="p-4 bg-gray-900/40 border border-gray-800 rounded-xl hover:border-gray-700 transition-colors">
        <span className="text-neon-purple font-display text-xs font-bold block mb-1">REGR {number}</span>
        <p className="text-gray-500 text-[10px] uppercase leading-tight">{text}</p>
    </div>
);

import React, { useEffect, useState, useCallback } from 'react';
import { TargetIcon } from './components/NeonIcons';
import { Podium } from './components/Podium';
import { RankingList } from './components/RankingList';
import { Overview } from './components/Overview';
import { LegendsView } from './components/LegendsView'; 
import { EyeMissclick } from './components/EyeMissclick'; 
import { aggregateData, fetchAndParseData, getOverviewStats } from './services/csvService';
import { RankedPlayer, RawDataRow, TimeFrame, OverviewData } from './types';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<TimeFrame>(TimeFrame.OVERVIEW);
  const [rawData, setRawData] = useState<RawDataRow[]>([]);
  const [rankedPlayers, setRankedPlayers] = useState<RankedPlayer[]>([]);
  const [overviewData, setOverviewData] = useState<OverviewData | null>(null);
  const [loading, setLoading] = useState(true);
  const [isRefreshing, setIsRefreshing] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const loadData = useCallback(async (isManualRefresh = false) => {
    if (isManualRefresh) setIsRefreshing(true);
    else setLoading(true);

    setError(null);
    try {
      const data = await fetchAndParseData();

      if (data.length === 0) {
        setError("Não foi possível carregar os dados. Verifique a planilha.");
      } else {
        setRawData(data);
        setOverviewData(getOverviewStats(data));

        if (activeTab !== TimeFrame.OVERVIEW && activeTab !== TimeFrame.SCANNER) {
          const ranked = aggregateData(data, activeTab);
          setRankedPlayers(ranked);
        }
      }
    } catch (err) {
      setError("Erro de conexão com o servidor de dados.");
    } finally {
      setLoading(false);
      setIsRefreshing(false);
    }
  }, [activeTab]);

  useEffect(() => {
    loadData();
  }, []); 

  useEffect(() => {
    if (rawData.length > 0 && activeTab !== TimeFrame.OVERVIEW && activeTab !== TimeFrame.SCANNER) {
      const ranked = aggregateData(rawData, activeTab);
      setRankedPlayers(ranked);
    }
  }, [activeTab, rawData]);

  const tabs = [
    { id: TimeFrame.OVERVIEW, label: 'Painel', subLabel: 'Geral' },
    { id: TimeFrame.DAILY, label: 'Hoje', subLabel: '24h' },
    { id: TimeFrame.WEEKLY, label: 'Semana', subLabel: '7 Dias' },
    { id: TimeFrame.MONTHLY, label: 'Mês', subLabel: '30 Dias' },
    { id: TimeFrame.ALL_TIME, label: 'Lendas', subLabel: 'Eternos' },
    { id: TimeFrame.SCANNER, label: 'Scanner', subLabel: 'EyeMissclick' },
  ];

  return (
    <div className="min-h-screen bg-neon-dark text-white selection:bg-neon-blue selection:text-black font-sans overflow-x-hidden">

      {/* MJR Symbol - Canto Superior Direito (Estilo Fiel à Imagem) */}
      <div className="fixed top-4 right-4 md:top-8 md:right-8 z-[100] flex flex-col items-center justify-center w-16 h-16 bg-[#050510] border-2 border-neon-blue rounded-xl shadow-[0_0_15px_rgba(0,243,255,0.4)] pointer-events-none group">
        <svg 
          xmlns="http://www.w3.org/2000/svg" 
          fill="none" 
          viewBox="0 0 24 24" 
          strokeWidth={4} 
          stroke="currentColor" 
          className="w-7 h-7 text-neon-blue drop-shadow-[0_0_8px_rgba(0,243,255,1)]"
        >
          <path strokeLinecap="round" strokeLinejoin="round" d="M4.5 10.5L12 3m0 0l7.5 7.5M12 3v18" />
        </svg>
        <span className="font-display font-black text-[11px] text-neon-blue tracking-tighter drop-shadow-[0_0_5px_rgba(0,243,255,0.8)] mt-0.5">
          MJR
        </span>
      </div>

      {/* Background Decor */}
      <div className="fixed top-0 left-0 w-full h-full pointer-events-none overflow-hidden z-0">
         <div className="absolute -top-20 -left-20 w-96 h-96 bg-neon-purple opacity-5 blur-[100px] rounded-full" />
         <div className="absolute top-1/2 right-0 w-80 h-80 bg-neon-blue opacity-5 blur-[120px] rounded-full" />
      </div>

      <div className="relative z-10 container mx-auto px-4 py-8">

