import React, { useState, useRef } from 'react';
import { GoogleGenAI } from "@google/genai";
import { ValidationResult } from '../types';

export const EyeMissclick: React.FC = () => {
  const [image, setImage] = useState<string | null>(null);
  const [isScanning, setIsScanning] = useState(false);
  const [result, setResult] = useState<ValidationResult | null>(null);
  const [error, setError] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setImage(reader.result as string);
        setResult(null);
        setError(null);
      };
      reader.readAsDataURL(file);
    }
  };

  const scanImage = async () => {
    if (!image) return;
    setIsScanning(true);
    setError(null);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const base64Data = image.split(',')[1];

      const prompt = `
        Aja como o sistema EyeMissclick, um validador de prints do jogo Tibia.
        Analise a imagem para os seguintes critérios:
        1. Hunt Analyser: Deve estar aberto com Session Time e Kills visíveis.
        2. Stamina: Janela ou barra de stamina deve estar visível.
        3. VIP List: Janela de VIP List deve estar aberta.
        4. Regra 2.2 (Solo): Verifique se há textos como "ks com [nome]" ou logs que indiquem ajuda de outros jogadores. O registro deve ser pessoal e intransferível.

        Responda EXATAMENTE neste formato (sem explicações extras):
        HUNT: [OK/ERRO]
        STAMINA: [OK/ERRO]
        VIP: [OK/ERRO]
        SOLO: [OK/ERRO]
        RESUMO: [Breve comentário em português]
      `;

      const response = await ai.models.generateContent({
        model: 'gemini-2.5-flash-image',
        contents: {
          parts: [
            { inlineData: { data: base64Data, mimeType: 'image/jpeg' } },
            { text: prompt }
          ]
        }
      });

      const text = response.text || "";
      const hunt = text.includes('HUNT: OK');
      const stamina = text.includes('STAMINA: OK');
      const vip = text.includes('VIP: OK');
      const solo = text.includes('SOLO: OK');
      const detailsMatch = text.match(/RESUMO: (.*)/);
      const details = detailsMatch ? detailsMatch[1] : "Análise neural concluída.";

      setResult({
        success: hunt && stamina && vip && solo,
        huntAnalyser: hunt,
        stamina: stamina,
        vipList: vip,
        personalRecord: solo,
        details: details
      });

    } catch (err) {
      console.error(err);
      setError("Falha na varredura neural. Tente novamente.");
    } finally {
      setIsScanning(false);
    }
  };

  return (
    <div className="max-w-4xl mx-auto px-4 py-8 animate-fade-in">
      <div className="text-center mb-10">
        <h2 className="text-5xl font-display font-black text-white uppercase tracking-tighter">
          Eye<span className="text-neon-blue">Missclick</span>
        </h2>
        <p className="text-gray-500 text-[10px] tracking-[0.5em] uppercase mt-2 opacity-60">AI Verification Core</p>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
        <div className="space-y-4">
          <div 
            onClick={() => !isScanning && fileInputRef.current?.click()}
            className={`
              relative aspect-video rounded-3xl border-2 transition-all duration-500 overflow-hidden cursor-pointer
              ${image ? 'border-neon-blue' : 'border-gray-800 hover:border-neon-purple bg-white/5'}
            `}
          >
            {image ? (
              <>
                <img src={image} alt="Print Preview" className={`w-full h-full object-cover ${isScanning ? 'opacity-40 grayscale' : 'opacity-80'}`} />
                {isScanning && (
                  <div className="absolute inset-0 z-10">
                    <div className="absolute top-0 left-0 w-full h-1 bg-neon-blue shadow-neon-blue animate-[scan_2s_linear_infinite]"></div>
                    <div className="absolute inset-0 bg-neon-blue/10 animate-pulse"></div>
                  </div>
                )}
              </>
            ) : (
              <div className="absolute inset-0 flex flex-col items-center justify-center gap-4">
                <div className="w-12 h-12 rounded-full border border-gray-700 flex items-center justify-center">
                   <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1} stroke="currentColor" className="w-6 h-6 text-gray-500">
                     <path strokeLinecap="round" strokeLinejoin="round" d="M3 16.5v2.25A2.25 2.25 0 005.25 21h13.5A2.25 2.25 0 0021 18.75V16.5m-13.5-9L12 3m0 0l4.5 4.5M12 3v13.5" />
                   </svg>
                </div>
                <p className="text-gray-500 font-display text-[10px] tracking-widest uppercase">Upload da Print de Validação</p>
              </div>
            )}
            <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={handleFileChange} />
          </div>

          <button
            onClick={scanImage}
            disabled={!image || isScanning}
            className={`
              w-full py-4 rounded-2xl font-display font-black tracking-[0.3em] uppercase transition-all
              ${!image || isScanning ? 'bg-gray-900 text-gray-600' : 'bg-neon-blue text-black hover:scale-[1.02] shadow-neon-blue'}
            `}
          >
            {isScanning ? 'Varredura em Curso...' : 'Validar Protocolo'}
          </button>
        </div>

        <div className="bg-neon-surface border border-gray-800 rounded-3xl p-6 flex flex-col gap-4">
           <h3 className="text-white font-display text-xs uppercase tracking-widest mb-2 flex items-center gap-2">
             <span className="w-2 h-2 bg-neon-purple rounded-full"></span> Diagnóstico MJR
           </h3>

           {!result && !error && !isScanning && (
             <div className="flex-1 flex flex-col items-center justify-center text-center opacity-20">
                <p className="text-[10px] uppercase tracking-widest">Aguardando dados...</p>
             </div>
           )}

           {isScanning && (
             <div className="flex-1 flex flex-col items-center justify-center text-center">
                <div className="w-8 h-8 border-2 border-neon-blue border-t-transparent rounded-full animate-spin mb-4"></div>
                <p className="text-neon-blue text-[10px] uppercase tracking-widest animate-pulse">Processando Visão...</p>
             </div>
           )}

           {result && (
             <div className="space-y-3 animate-fade-in">
                <CheckItem label="Hunt Analyser (2.3)" passed={result.huntAnalyser} />
                <CheckItem label="Stamina (2.3)" passed={result.stamina} />
                <CheckItem label="VIP List (2.3)" passed={result.vipList} />
                <CheckItem label="Registro Solo (2.2)" passed={result.personalRecord} />

                <div className="mt-6 p-4 bg-black/40 rounded-xl border border-gray-800">
                  <span className="text-[9px] text-gray-500 uppercase block mb-1 tracking-widest">Parecer da IA:</span>
                  <p className="text-gray-300 text-[11px] leading-relaxed italic">"{result.details}"</p>
                </div>

                <div className={`mt-4 py-3 rounded-lg text-center font-display text-xs font-bold uppercase tracking-widest border ${result.success ? 'bg-neon-green/10 text-neon-green border-neon-green/50' : 'bg-red-500/10 text-red-500 border-red-500/50'}`}>
                  {result.success ? 'Protocolo Aprovado' : 'Protocolo Negado'}
                </div>
             </div>
           )}
        </div>
      </div>

      <style>{`
        @keyframes scan {
          0% { top: 0%; }
          100% { top: 100%; }
        }
      `}</style>
    </div>
  );
};

const CheckItem: React.FC<{ label: string, passed: boolean }> = ({ label, passed }) => (
  <div className="flex items-center justify-between p-3 bg-white/5 rounded-xl border border-gray-800/50">
    <span className="text-gray-400 text-[10px] uppercase tracking-wider">{label}</span>
    <span className={`font-black text-[10px] ${passed ? 'text-neon-green' : 'text-red-500'}`}>
      {passed ? 'DETEC.' : 'FALHA'}
    </span>
  </div>
);

import React, { useEffect, useState, useCallback } from 'react';
import { TargetIcon } from './components/NeonIcons';
import { Podium } from './components/Podium';
import { RankingList } from './components/RankingList';
import { Overview } from './components/Overview';
import { LegendsView } from './components/LegendsView'; 
import { EyeMissclick } from './components/EyeMissclick';
import { aggregateData, fetchAndParseData, getOverviewStats } from './services/csvService';
import { RankedPlayer, RawDataRow, TimeFrame, OverviewData } from './types';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<TimeFrame>(TimeFrame.OVERVIEW);
  const [rawData, setRawData] = useState<RawDataRow[]>([]);
  const [rankedPlayers, setRankedPlayers] = useState<RankedPlayer[]>([]);
  const [overviewData, setOverviewData] = useState<OverviewData | null>(null);
  const [loading, setLoading] = useState(true);
  const [isRefreshing, setIsRefreshing] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const loadData = useCallback(async (isManualRefresh = false) => {
    if (isManualRefresh) setIsRefreshing(true);
    else setLoading(true);

    setError(null);
    try {
      const data = await fetchAndParseData();

      if (data.length === 0) {
        setError("Não foi possível carregar os dados. Verifique a planilha.");
      } else {
        setRawData(data);
        setOverviewData(getOverviewStats(data));

        if (activeTab !== TimeFrame.OVERVIEW && activeTab !== TimeFrame.SCANNER) {
          const ranked = aggregateData(data, activeTab);
          setRankedPlayers(ranked);
        }
      }
    } catch (err) {
      setError("Erro de conexão com o banco de dados MJR.");
    } finally {
      setLoading(false);
      setIsRefreshing(false);
    }
  }, [activeTab]);

  useEffect(() => {
    loadData();
  }, []); 

  useEffect(() => {
    if (rawData.length > 0 && activeTab !== TimeFrame.OVERVIEW && activeTab !== TimeFrame.SCANNER) {
      const ranked = aggregateData(rawData, activeTab);
      setRankedPlayers(ranked);
    }
  }, [activeTab, rawData]);

  const tabs = [
    { id: TimeFrame.OVERVIEW, label: 'Overview', subLabel: 'Geral' },
    { id: TimeFrame.SCANNER, label: 'EyeMissclick', subLabel: 'AI Scanner' },
    { id: TimeFrame.DAILY, label: 'Hoje', subLabel: '24h' },
    { id: TimeFrame.WEEKLY, label: 'Semana', subLabel: '7 Dias' },
    { id: TimeFrame.MONTHLY, label: 'Mês', subLabel: '30 Dias' },
    { id: TimeFrame.ALL_TIME, label: 'Legends', subLabel: 'Eternos' },
  ];

  return (
    <div className="min-h-screen bg-neon-dark text-white selection:bg-neon-blue selection:text-black font-sans overflow-x-hidden">

      {/* MJR Symbol */}
      <div className="fixed top-6 right-6 z-50 flex flex-col items-center justify-center w-14 h-14 bg-black/40 border-2 border-neon-blue rounded-xl shadow-neon-blue pointer-events-none">
        <svg 
          xmlns="http://www.w3.org/2000/svg" 
          fill="none" 
          viewBox="0 0 24 24" 
          strokeWidth={4} 
          stroke="currentColor" 
          className="w-6 h-6 text-neon-blue drop-shadow-[0_0_5px_#00f3ff]"
        >
          <path strokeLinecap="round" strokeLinejoin="round" d="M4.5 10.5L12 3m0 0l7.5 7.5M12 3v18" />
        </svg>
        <span className="font-display font-black text-[10px] text-neon-blue mt-0.5 tracking-tighter drop-shadow-[0_0_3px_#00f3ff]">
          MJR
        </span>
      </div>

      <div className="fixed top-0 left-0 w-full h-full pointer-events-none overflow-hidden z-0">
         <div className="absolute -top-20 -left-20 w-96 h-96 bg-neon-purple opacity-10 blur-[100px] rounded-full" />
         <div className="absolute top-1/2 right-0 w-80 h-80 bg-neon-blue opacity-10 blur-[120px] rounded-full" />
      </div>

      <div className="relative z-10 container mx-auto px-4 py-8">
        <header className="flex flex-col items-center mb-10 text-center">
          <div className="relative mb-2">
            <h1 className="text-4xl md:text-6xl font-display font-black tracking-tighter text-transparent bg-clip-text bg-gradient-to-r from-neon-blue via-white to-neon-purple drop-shadow-lg">
              MissclicKS
            </h1>
            <div className="absolute -inset-1 blur-lg bg-neon-blue opacity-20 animate-pulse"></div>
          </div>
          <p className="text-neon-blue tracking-widest text-[10px] uppercase opacity-60 flex items-center gap-2">
            <TargetIcon className="w-3 h-3" /> Kill Score Tracking System
          </p>
        </header>

        <nav className="flex justify-center mb-10 overflow-x-auto pb-4 px-2 no-scrollbar">
            <div className="flex bg-neon-surface/80 backdrop-blur-md border border-gray-800 p-1 rounded-2xl gap-1">
                {tabs.map((tab) => (
                <button
                    key={tab.id}
                    onClick={() => setActiveTab(tab.id)}
                    className={`
                    relative px-4 md:px-6 py-2 rounded-xl transition-all duration-300 flex flex-col items-center justify-center min-w-[100px] whitespace-nowrap
                    ${activeTab === tab.id 
                        ? (tab.id === TimeFrame.SCANNER ? 'text-black bg-neon-blue shadow-neon-blue' : (tab.id === TimeFrame.ALL_TIME ? 'text-black bg-gradient-to-r from-yellow-400 to-yellow-600 shadow-xl' : 'text-black bg-white shadow-xl')) 
                        : 'text-gray-400 hover:text-white hover:bg-white/5'}
                    `}
                >
                    <span className="font-display font-bold text-[10px] md:text-xs uppercase">{tab.label}</span>
                    <span className={`text-[8px] md:text-[10px] ${activeTab === tab.id ? 'text-black/60 font-bold' : 'text-gray-600'}`}>{tab.subLabel}</span>
                </button>
                ))}
            </div>
        </nav>

        {loading ? (
          <div className="flex flex-col justify-center items-center h-64 gap-4">
            <div className="w-10 h-10 border-2 border-neon-blue border-t-transparent rounded-full animate-spin"></div>
            <p className="font-display text-[10px] text-gray-500 uppercase tracking-widest">Sincronizando Core...</p>
          </div>
        ) : error ? (
            <div className="text-center p-8 bg-neon-surface border border-red-500/20 rounded-3xl max-w-lg mx-auto animate-fade-in">
                <p className="text-red-400 font-bold mb-2 uppercase tracking-widest">System Error</p>
                <p className="text-gray-500 text-xs mb-6">{error}</p>
                <button 
                    onClick={() => loadData()}
                    className="px-8 py-3 bg-white text-black hover:bg-neon-blue transition-all rounded-full text-[10px] uppercase font-black tracking-widest shadow-xl"
                >
                    Retry Connection
                </button>
            </div>
        ) : (
          <main className="animate-fade-in">
            {activeTab === TimeFrame.OVERVIEW ? (
                 overviewData && <Overview data={overviewData} />
            ) : activeTab === TimeFrame.SCANNER ? (
                 <EyeMissclick />
            ) : activeTab === TimeFrame.ALL_TIME ? (
                 <LegendsView players={rankedPlayers} />
            ) : (
                <>
                    <div className="mb-4 text-center">
                    <h2 className="text-2xl font-display text-white mb-1 uppercase tracking-tight">
                        Ranking {tabs.find(t => t.id === activeTab)?.label}
                    </h2>
                    </div>

                    {rankedPlayers.length === 0 ? (
                        <div className="text-center py-20 opacity-30 border-2 border-dashed border-gray-800 rounded-3xl mx-auto max-w-2xl mt-8">
                            <p className="font-display text-lg text-gray-400">Nenhum dado encontrado para este período.</p>
                        </div>
                    ) : (
                        <>
                            <Podium players={rankedPlayers} />
                            <RankingList players={rankedPlayers} />
                        </>
                    )}
                </>
            )}
          </main>
        )}
      </div>

      <button 
        onClick={() => loadData(true)}
        disabled={isRefreshing || loading}
        className={`fixed bottom-6 right-6 w-12 h-12 bg-neon-surface border border-gray-800 rounded-full flex items-center justify-center text-gray-400 hover:text-neon-blue hover:border-neon-blue transition-all shadow-lg z-50 group ${isRefreshing ? 'cursor-not-allowed opacity-50' : 'hover:scale-110 active:scale-95'}`}
      >
        <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={2} stroke="currentColor" className={`w-5 h-5 ${isRefreshing ? 'animate-spin' : ''}`}>
          <path strokeLinecap="round" strokeLinejoin="round" d="M16.023 9.348h4.992v-.001M2.985 19.644v-4.992m0 0h4.992m-4.993 0l3.181 3.183a8.25 8.25 0 0013.803-3.7M4.031 9.865a8.25 8.25 0 0113.803-3.7l3.181 3.182m0-4.991v4.99" />
        </svg>
      </button>

      <footer className="text-center py-12 text-gray-700 text-[10px] tracking-[0.5em] uppercase">
         <p>MissclicKS Core &copy; {new Date().getFullYear()} // Protocolo Operacional</p>
      </footer>
    </div>
  );
};

export default App;

export enum TimeFrame {
  OVERVIEW = 'OVERVIEW',
  SCANNER = 'SCANNER',
  DAILY = 'DAILY',
  WEEKLY = 'WEEKLY',
  MONTHLY = 'MONTHLY',
  ALL_TIME = 'ALL_TIME'
}

export interface RawDataRow {
  player: string;
  ks: number;
  date: string; // ISO string or simple date string
  playerRank: string; // Column D data
  respawn: string; // Column F data
}

export interface RankedPlayer {
  rank: number;
  name: string;
  totalKS: number;
  gamesPlayed: number;
  averageKS: number;
  trend: 'up' | 'down' | 'same'; // Visual indicator
}

export interface ValidationResult {
  success: boolean;
  huntAnalyser: boolean;
  stamina: boolean;
  vipList: boolean;
  personalRecord: boolean;
  details: string;
}

export interface OverviewData {
  totalKills: number;
  totalRecords: number;
  busiestDay: string;
  avgKillsPerDay: number;
  hourlyDistribution: number[]; // 0-23 hours
  weeklyDistribution: number[]; // 0-6 (Sun-Sat)
  dailyTrend: { date: string; count: number }[]; // Last 14 days
  weightDistribution: { normal: number; heavy: number };
  killsByRank: { rank: string; count: number }[]; 
  topRespawns: { name: string; count: number }[]; // New Top 5 Respawns
  recentActivity: RawDataRow[]; // New: Last 5 logs
  dominationStats: { name: string; percentage: number; count: number }[]; // New: Top 5 players % share
}

export interface RankingData {
  timeFrame: TimeFrame;
  lastUpdated: string;
  players: RankedPlayer[];
}

import React, { useState, useRef } from 'react';
import { GoogleGenAI } from "@google/genai";
import { ValidationResult } from '../types';

export const EyeMissclick: React.FC = () => {
  const [image, setImage] = useState<string | null>(null);
  const [isScanning, setIsScanning] = useState(false);
  const [result, setResult] = useState<ValidationResult | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [progress, setProgress] = useState(0);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setImage(reader.result as string);
        setResult(null);
        setError(null);
        setProgress(0);
      };
      reader.readAsDataURL(file);
    }
  };

  const scanImage = async () => {
    if (!image) return;

    setIsScanning(true);
    setError(null);
    setProgress(10);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const base64Data = image.split(',')[1];

      setProgress(30);

      const prompt = `
        Aja como o sistema EyeMissclick. Sua missão é validar se esta print de Tibia cumpre os critérios obrigatórios para registro de KS:

        CRITÉRIOS DE VALIDAÇÃO:
        1. HUNT ANALYSER: A janela deve estar aberta com "Session" e "Loot/Kills" claramente visíveis.
        2. STAMINA: A barra ou janela de stamina deve estar presente na tela.
        3. VIP LIST: A janela VIP List deve estar aberta.
        4. SOLO (REGRA 2.2): Não pode haver menção a "ks com", "ajuda de" ou marcas de outros players que invalidem o registro pessoal. O registro deve ser individual.

        FORMATO DE RESPOSTA (Obrigatório, apenas estas linhas):
        HUNT_STATUS: [OK/ERRO]
        STAMINA_STATUS: [OK/ERRO]
        VIP_STATUS: [OK/ERRO]
        SOLO_STATUS: [OK/ERRO]
        RESUMO: [Breve comentário técnico em português sobre o que encontrou]
      `;

      setProgress(50);

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: {
          parts: [
            { inlineData: { data: base64Data, mimeType: 'image/jpeg' } },
            { text: prompt }
          ]
        }
      });

      setProgress(80);
      const text = response.text || "";

      // Parsing robusto dos resultados
      const hunt = text.toUpperCase().includes('HUNT_STATUS: OK');
      const stamina = text.toUpperCase().includes('STAMINA_STATUS: OK');
      const vip = text.toUpperCase().includes('VIP_STATUS: OK');
      const solo = text.toUpperCase().includes('SOLO_STATUS: OK');
      const detailsMatch = text.match(/RESUMO: (.*)/i);
      const details = detailsMatch ? detailsMatch[1] : "Varredura concluída pelos sistemas MJR.";

      setResult({
        success: hunt && stamina && vip && solo,
        huntAnalyser: hunt,
        stamina: stamina,
        vipList: vip,
        personalRecord: solo,
        details: details
      });
      setProgress(100);

    } catch (err: any) {
      console.error("Erro no EyeMissclick:", err);
      if (err.message?.includes('API_KEY')) {
        setError("Chave de API inválida ou ausente. Verifique as configurações do servidor.");
      } else {
        setError("Falha na conexão neural. O servidor MJR não pôde processar a imagem.");
      }
    } finally {
      setIsScanning(false);
    }
  };

  return (
    <div className="max-w-4xl mx-auto px-4 py-8 animate-fade-in mb-20">
      <div className="text-center mb-10">
        <div className="inline-block relative">
            <h2 className="text-5xl font-display font-black text-white uppercase tracking-tighter">
              Eye<span className="text-neon-blue">Missclick</span>
            </h2>
            <div className="absolute -bottom-2 left-0 w-full h-1 bg-gradient-to-r from-transparent via-neon-blue to-transparent shadow-neon-blue"></div>
        </div>
        <p className="text-gray-500 text-[10px] tracking-[0.5em] uppercase mt-4 opacity-60">Protocolo de Visão Artificial 3.0</p>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 items-start">

        {/* Painel de Upload */}
        <div className="space-y-6">
          <div 
            onClick={() => !isScanning && fileInputRef.current?.click()}
            className={`
              relative aspect-video rounded-3xl border-2 transition-all duration-700 overflow-hidden group
              ${image ? 'border-neon-blue shadow-neon-blue/20' : 'border-gray-800 hover:border-neon-purple bg-black/40'}
              ${isScanning ? 'cursor-wait' : 'cursor-pointer'}
            `}
          >
            {image ? (
              <>
                <img src={image} alt="Preview" className={`w-full h-full object-cover transition-opacity duration-500 ${isScanning ? 'opacity-40 grayscale' : 'opacity-80'}`} />

                {/* Animação de Scanner Laser */}
                {isScanning && (
                  <div className="absolute inset-0 z-20 overflow-hidden">
                    <div className="absolute top-0 left-0 w-full h-1 bg-neon-blue shadow-[0_0_15px_#00f3ff] animate-[scan_2s_linear_infinite]"></div>
                    <div className="absolute inset-0 bg-neon-blue/5 animate-pulse"></div>
                  </div>
                )}

                <div className="absolute inset-0 flex items-center justify-center bg-black/60 opacity-0 group-hover:opacity-100 transition-opacity">
                  <span className="bg-white/10 backdrop-blur-md px-4 py-2 rounded-full border border-white/20 text-xs font-bold uppercase tracking-widest text-white">Trocar Screenshot</span>
                </div>
              </>
            ) : (
              <div className="absolute inset-0 flex flex-col items-center justify-center gap-4">
                <div className="w-16 h-16 rounded-full bg-gray-900 border border-gray-800 flex items-center justify-center group-hover:scale-110 group-hover:border-neon-purple transition-all">
                  <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1} stroke="currentColor" className="w-8 h-8 text-gray-500 group-hover:text-neon-purple">
                    <path strokeLinecap="round" strokeLinejoin="round" d="M6.827 6.175A2.31 2.31 0 015.186 7.23c-.38.054-.757.112-1.134.175C2.999 7.58 2.25 8.507 2.25 9.574V18a2.25 2.25 0 002.25 2.25h15a2.25 2.25 0 002.25-2.25V9.574c0-1.067-.75-1.994-1.802-2.169a47.865 47.865 0 00-1.134-.175 2.31 2.31 0 01-1.64-1.055l-.822-1.316a2.192 2.192 0 00-1.736-1.039 48.774 48.774 0 00-5.232 0 2.192 2.192 0 00-1.736 1.039l-.821 1.316z" />
                    <path strokeLinecap="round" strokeLinejoin="round" d="M16.5 12.75a4.5 4.5 0 11-9 0 4.5 4.5 0 019 0zM18.75 10.5h.008v.008h-.008V10.5z" />
                  </svg>
                </div>
                <p className="text-gray-500 font-display text-[10px] tracking-widest uppercase">Solte sua prova de KS aqui</p>
              </div>
            )}
            <input 
              type="file" 
              ref={fileInputRef} 
              className="hidden" 
              accept="image/*" 
              onChange={handleFileChange} 
            />
          </div>

          <button
            onClick={scanImage}
            disabled={!image || isScanning}
            className={`
              w-full py-4 rounded-2xl font-display font-black tracking-[0.3em] uppercase transition-all relative overflow-hidden group
              ${!image || isScanning 
                ? 'bg-gray-900 text-gray-600 cursor-not-allowed border border-gray-800' 
                : 'bg-white text-black hover:bg-neon-blue shadow-xl hover:shadow-neon-blue active:scale-95'}
            `}
          >
            {isScanning ? (
              <span className="flex items-center justify-center gap-3">
                <span className="w-2 h-2 bg-black rounded-full animate-ping"></span>
                Analisando Protocolo...
              </span>
            ) : 'Validar Prova'}

            {isScanning && (
               <div 
                style={{ width: `${progress}%` }}
                className="absolute bottom-0 left-0 h-1 bg-neon-purple transition-all duration-500 shadow-[0_0_10px_#bc13fe]"
               />
            )}
          </button>
        </div>

        {/* Resultados */}
        <div className="bg-neon-surface border border-gray-800 rounded-3xl p-8 relative min-h-[420px] flex flex-col">
          <div className="flex items-center justify-between mb-8">
            <h3 className="text-white font-display text-xs tracking-widest uppercase flex items-center gap-3">
              <span className={`w-3 h-3 rounded-full ${isScanning ? 'bg-yellow-500 animate-pulse' : (result ? (result.success ? 'bg-neon-green' : 'bg-red-500') : 'bg-gray-700')}`}></span>
              Status do Diagnóstico
            </h3>
            {result && (
               <span className={`text-[10px] font-bold px-2 py-1 rounded border ${result.success ? 'border-neon-green text-neon-green' : 'border-red-500 text-red-500'}`}>
                 CODE: {result.success ? 'APPROVE_200' : 'DENIED_403'}
               </span>
            )}
          </div>

          {!result && !error && !isScanning && (
            <div className="flex-1 flex flex-col items-center justify-center text-center space-y-4 opacity-20">
              <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={0.5} stroke="currentColor" className="w-24 h-24">
                <path strokeLinecap="round" strokeLinejoin="round" d="M12 21a9.004 9.004 0 008.716-6.747M12 21a9.004 9.004 0 01-8.716-6.747M12 21c2.485 0 4.5-4.03 4.5-9S14.485 3 12 3m0 18c-2.485 0-4.5-4.03-4.5-9S9.515 3 12 3m0 0a8.997 8.997 0 017.843 4.582M12 3a8.997 8.997 0 00-7.843 4.582m15.686 0A11.953 11.953 0 0112 10.5c-2.998 0-5.74-1.1-7.843-2.918m15.686 0A8.959 8.959 0 0121 12c0 .778-.099 1.533-.284 2.253m0 0A17.919 17.919 0 0112 16.5c-3.162 0-6.133-.815-8.716-2.247m0 0A9.015 9.015 0 013 12c0-1.605.42-3.113 1.157-4.418" />
              </svg>
              <p className="text-xs uppercase tracking-[0.3em]">IA em Standby</p>
            </div>
          )}

          {isScanning && (
            <div className="flex-1 flex flex-col items-center justify-center space-y-6">
               <div className="relative w-20 h-20">
                  <div className="absolute inset-0 border-4 border-neon-blue/20 rounded-full"></div>
                  <div className="absolute inset-0 border-4 border-neon-blue border-t-transparent rounded-full animate-spin"></div>
               </div>
               <div className="space-y-2 text-center">
