        const hour = dateMatch[4] ? parseInt(dateMatch[4]) : 0;
        const minute = dateMatch[5] ? parseInt(dateMatch[5]) : 0;

        return new Date(year, month, day, hour, minute);
    }

    const iso = new Date(cleanStr);
    return isNaN(iso.getTime()) ? null : iso;
};

