          <div className="absolute inset-0 opacity-[0.03] pointer-events-none bg-[url('https://www.transparenttextures.com/patterns/carbon-fibre.png')]"></div>

          {blacklisted.length === 0 ? (
              <div className="py-20 flex flex-col items-center justify-center text-center">
                  <div className="w-20 h-20 bg-zinc-900 border border-zinc-800 rounded-full flex items-center justify-center mb-6">
                      <AlertIcon className="w-10 h-10 text-zinc-700" />
                  </div>
                  <h3 className="text-zinc-500 font-display text-sm tracking-widest uppercase">No hostile targets identified</h3>
                  <p className="text-zinc-700 text-xs mt-2 font-mono">System monitoring remains active.</p>
