          ) : (
              <div className="grid grid-cols-1 gap-4">
                  {blacklisted.map((target, i) => (
                      <div key={i} className="group relative bg-black border border-red-900/50 p-4 rounded-lg flex items-center justify-between hover:border-red-600 transition-all duration-300">

