                          <div className="flex items-center gap-5 z-10">
                              <div className="w-12 h-12 bg-zinc-900 border border-red-900 flex items-center justify-center rounded">
                                  <SkullIcon className="w-6 h-6 text-red-600 group-hover:scale-110 transition-transform" />
                              </div>
                              <div>
                                  <h4 className="text-white font-display font-bold text-lg tracking-tighter group-hover:text-red-500 transition-colors">
                                      {target.name}
                                  </h4>
                                  <div className="flex items-center gap-2 mt-1">
