import React, { useEffect, useState, useCallback } from 'react';
import { TargetIcon } from './components/NeonIcons';
import { Podium } from './components/Podium';
import { RankingList } from './components/RankingList';
import { Overview } from './components/Overview';
import { LegendsView } from './components/LegendsView'; 
import { BlackListView } from './components/BlackListView';
import { aggregateData, fetchAndParseData, getOverviewStats } from './services/csvService';
import { RankedPlayer, RawDataRow, TimeFrame, OverviewData } from './types';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<TimeFrame>(TimeFrame.OVERVIEW);
  const [rawData, setRawData] = useState<RawDataRow[]>([]);
  const [rankedPlayers, setRankedPlayers] = useState<RankedPlayer[]>([]);
  const [overviewData, setOverviewData] = useState<OverviewData | null>(null);
  const [loading, setLoading] = useState(true);
  const [isRefreshing, setIsRefreshing] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Reusable data fetch function
  const loadData = useCallback(async (isManualRefresh = false) => {
    if (isManualRefresh) setIsRefreshing(true);
    else setLoading(true);

    setError(null);
    try {
      const data = await fetchAndParseData();

      if (data.length === 0) {
        setError("Unable to load data. The spreadsheet might be empty, formatted incorrectly, or inaccessible.");
      } else {
        setRawData(data);
        setOverviewData(getOverviewStats(data));

        // If we are not in overview or blacklist, update the current tab's ranking immediately
        if (activeTab !== TimeFrame.OVERVIEW && activeTab !== TimeFrame.BLACK_LIST) {
          const ranked = aggregateData(data, activeTab);
          setRankedPlayers(ranked);
        }
      }
    } catch (err) {
      setError("A connection error occurred while fetching combat data.");
    } finally {
      setLoading(false);
      setIsRefreshing(false);
    }
  }, [activeTab]);

  // Initial Data Fetch
  useEffect(() => {
    loadData();
  }, []); // Only run once on mount

  // Update rankings when tab changes (based on existing rawData)
  useEffect(() => {
    if (rawData.length > 0 && activeTab !== TimeFrame.OVERVIEW && activeTab !== TimeFrame.BLACK_LIST) {
      const ranked = aggregateData(rawData, activeTab);
      setRankedPlayers(ranked);
    }
  }, [activeTab, rawData]);

  const tabs = [
    { id: TimeFrame.OVERVIEW, label: 'Overview', subLabel: 'System Stats' },
    { id: TimeFrame.BLACK_LIST, label: 'Black List', subLabel: 'Infamous' },
    { id: TimeFrame.DAILY, label: 'Today', subLabel: 'Last 24h' },
    { id: TimeFrame.WEEKLY, label: 'Weekly', subLabel: 'Last 7 Days' },
    { id: TimeFrame.MONTHLY, label: 'Monthly', subLabel: 'Last 30 Days' },
    { id: TimeFrame.ALL_TIME, label: 'Legends', subLabel: 'All Time' },
  ];

  return (
    <div className="min-h-screen bg-neon-dark text-white selection:bg-neon-blue selection:text-black font-sans overflow-x-hidden">

      {/* Background Decor */}
      <div className="fixed top-0 left-0 w-full h-full pointer-events-none overflow-hidden z-0">
         <div className="absolute -top-20 -left-20 w-96 h-96 bg-neon-purple opacity-10 blur-[100px] rounded-full" />
         <div className="absolute top-1/2 right-0 w-80 h-80 bg-neon-blue opacity-10 blur-[120px] rounded-full" />
      </div>

      <div className="relative z-10 container mx-auto px-4 py-8">

        {/* Header */}
        <header className="flex flex-col items-center mb-10">
          <div className="relative mb-2">
            <h1 className="text-4xl md:text-6xl font-display font-black tracking-tighter text-transparent bg-clip-text bg-gradient-to-r from-neon-blue via-white to-neon-purple drop-shadow-lg">
              MissclicKS
            </h1>
            <div className="absolute -inset-1 blur-lg bg-neon-blue opacity-20 animate-pulse"></div>
          </div>
          <p className="text-neon-blue tracking-widest text-xs uppercase opacity-80 flex items-center gap-2">
            <TargetIcon className="w-4 h-4" /> Kill Score Tracker
          </p>
        </header>

        {/* Navigation Tabs */}
        <div className="flex justify-center mb-10">
            <div className="flex flex-wrap justify-center p-1 bg-neon-surface border border-gray-800 rounded-xl gap-1">
                {tabs.map((tab) => (
                <button
                    key={tab.id}
                    onClick={() => setActiveTab(tab.id)}
                    className={`
                    relative px-4 md:px-6 py-2 rounded-lg transition-all duration-300 flex flex-col items-center justify-center min-w-[100px]
                    ${activeTab === tab.id 
                        ? (tab.id === TimeFrame.ALL_TIME 
                            ? 'text-black bg-gradient-to-r from-yellow-400 to-yellow-600 shadow-[0_0_15px_rgba(234,179,8,0.6)]' 
                            : tab.id === TimeFrame.BLACK_LIST 
                                ? 'text-white bg-red-600 shadow-[0_0_20px_rgba(220,38,38,0.6)]' 
                                : 'text-black bg-neon-blue shadow-[0_0_15px_rgba(0,243,255,0.5)]') 
                        : 'text-gray-400 hover:text-white hover:bg-white/5'}
                    `}
                >
                    <span className="font-display font-bold text-sm uppercase">{tab.label}</span>
                    <span className={`text-[10px] ${activeTab === tab.id ? 'text-white/80 font-bold' : 'text-gray-600'}`}>{tab.subLabel}</span>
                </button>
                ))}
            </div>
        </div>

        {/* Content Area */}
        {loading ? (
          <div className="flex justify-center items-center h-64">
            <div className="w-12 h-12 border-4 border-neon-blue border-t-transparent rounded-full animate-spin"></div>
          </div>
        ) : error ? (
            <div className="text-center p-8 bg-neon-surface border border-red-500/50 rounded-xl max-w-lg mx-auto">
                <p className="text-red-400 font-bold mb-2">System Error</p>
                <p className="text-gray-400 text-sm mb-4">{error}</p>
                <p className="text-xs text-gray-500">Ensure the Google Sheet is "Published to Web" as CSV.</p>
                <button 
                    onClick={() => loadData()}
                    className="mt-4 px-6 py-2 bg-red-500/20 hover:bg-red-500/40 text-red-300 rounded border border-red-500/50 transition-colors"
                >
                    Retry Connection
                </button>
            </div>
        ) : (
          <main className="animate-fade-in">
            {activeTab === TimeFrame.OVERVIEW ? (
                 overviewData && <Overview data={overviewData} />
            ) : activeTab === TimeFrame.BLACK_LIST ? (
                 <BlackListView rawData={rawData} />
            ) : activeTab === TimeFrame.ALL_TIME ? (
                 <LegendsView players={rankedPlayers} />
            ) : (
                <>
                    <div className="mb-4 text-center">
                    <h2 className="text-2xl font-display text-white mb-1">
                        {tabs.find(t => t.id === activeTab)?.label} Ranking
                    </h2>
                    <p className="text-gray-500 text-sm">
                        {activeTab === TimeFrame.DAILY && "KS confirmed today."}
                        {activeTab === TimeFrame.WEEKLY && "Performance over the last 7 days."}
                        {activeTab === TimeFrame.MONTHLY && "Performance over the last 30 days."}
                    </p>
                    </div>

                    {/* Empty State for Ranking */}
                    {rankedPlayers.length === 0 ? (
                        <div className="text-center py-20 opacity-50 bg-neon-surface/30 rounded-xl border border-dashed border-gray-800 mx-auto max-w-2xl mt-8">
                            <p className="font-display text-xl text-gray-400">No data found for this period.</p>
                            <p className="text-sm text-gray-600 mt-2">Start scoring KS to appear here!</p>
                        </div>
                    ) : (
                        <>
                            {/* Standard Neon Podium */}
                            <Podium players={rankedPlayers} />

                            {/* Standard Ranking List */}
                            <RankingList players={rankedPlayers} />
                        </>
                    )}
                </>
            )}
          </main>
        )}
      </div>

      {/* Floating Action Button (Internal Refresh) */}
      <button 
        onClick={() => loadData(true)}
        disabled={isRefreshing || loading}
        className={`fixed bottom-6 right-6 w-14 h-14 bg-neon-surface border border-neon-purple rounded-full flex items-center justify-center text-neon-purple hover:bg-neon-purple hover:text-white transition-all shadow-lg hover:shadow-neon-purple z-50 group ${isRefreshing ? 'cursor-not-allowed opacity-80' : ''}`}
        aria-label="Refresh Data"
      >
        <svg 
          xmlns="http://www.w3.org/2000/svg" 
          fill="none" 
          viewBox="0 0 24 24" 
          strokeWidth={2} 
          stroke="currentColor" 
          className={`w-7 h-7 ${isRefreshing ? 'animate-spin' : 'group-hover:rotate-180 transition-transform duration-700'}`}
        >
          <path strokeLinecap="round" strokeLinejoin="round" d="M16.023 9.348h4.992v-.001M2.985 19.644v-4.992m0 0h4.992m-4.993 0l3.181 3.183a8.25 8.25 0 0013.803-3.7M4.031 9.865a8.25 8.25 0 0113.803-3.7l3.181 3.182m0-4.991v4.99" />
        </svg>

        {/* Tooltip on hover */}
        {!isRefreshing && (
          <span className="absolute right-full mr-3 px-2 py-1 bg-black text-white text-[10px] font-bold uppercase tracking-widest rounded border border-gray-800 opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none whitespace-nowrap">
            Update Feed
          </span>
        )}
      </button>

      <footer className="text-center py-6 text-gray-600 text-xs">
         <p>MissclicKS &copy; {new Date().getFullYear()} // System Online</p>
      </footer>
    </div>
  );
};

export default App;

import React, { useEffect, useState, useCallback } from 'react';
import { TargetIcon } from './components/NeonIcons';
import { Podium } from './components/Podium';
import { RankingList } from './components/RankingList';
import { Overview } from './components/Overview';
import { LegendsView } from './components/LegendsView'; 
import { BlackListView } from './components/BlackListView';
import { aggregateData, fetchAndParseData, getOverviewStats } from './services/csvService';
import { RankedPlayer, RawDataRow, TimeFrame, OverviewData } from './types';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<TimeFrame>(TimeFrame.OVERVIEW);
  const [rawData, setRawData] = useState<RawDataRow[]>([]);
  const [rankedPlayers, setRankedPlayers] = useState<RankedPlayer[]>([]);
  const [overviewData, setOverviewData] = useState<OverviewData | null>(null);
  const [loading, setLoading] = useState(true);
  const [isRefreshing, setIsRefreshing] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const loadData = useCallback(async (isManualRefresh = false) => {
    if (isManualRefresh) setIsRefreshing(true);
    else setLoading(true);

    setError(null);
    try {
      const data = await fetchAndParseData();
      if (data.length === 0) {
        setError("Sincronização falhou. Verifique a fonte de dados.");
      } else {
        setRawData(data);
        setOverviewData(getOverviewStats(data));
        if (activeTab !== TimeFrame.OVERVIEW && activeTab !== TimeFrame.BLACK_LIST) {
          setRankedPlayers(aggregateData(data, activeTab));
        }
      }
    } catch (err) {
      setError("Erro de conexão com o banco de dados.");
    } finally {
      setLoading(false);
      setIsRefreshing(false);
    }
  }, [activeTab]);

  useEffect(() => { loadData(); }, []);

  useEffect(() => {
    if (rawData.length > 0 && activeTab !== TimeFrame.OVERVIEW && activeTab !== TimeFrame.BLACK_LIST) {
      setRankedPlayers(aggregateData(rawData, activeTab));
    }
  }, [activeTab, rawData]);

  const tabs = [
    { id: TimeFrame.OVERVIEW, label: 'Overview', subLabel: 'Stats', color: 'blue' },
    { id: TimeFrame.BLACK_LIST, label: 'Black List', subLabel: 'Banned', color: 'red' },
    { id: TimeFrame.DAILY, label: 'Hoje', subLabel: 'Daily', color: 'blue' },
    { id: TimeFrame.WEEKLY, label: 'Semana', subLabel: '7 Days', color: 'blue' },
    { id: TimeFrame.MONTHLY, label: 'Mês', subLabel: '30 Days', color: 'blue' },
    { id: TimeFrame.ALL_TIME, label: 'Hall', subLabel: 'Legends', color: 'yellow' },
  ];

  return (
    <div className="min-h-screen bg-black text-white font-sans selection:bg-neon-blue selection:text-black">

      {/* Luzes de Fundo (Ambiência) */}
      <div className="fixed inset-0 pointer-events-none z-0">
         <div className="absolute top-0 left-1/4 w-[500px] h-[500px] bg-neon-blue/5 blur-[120px] rounded-full animate-pulse" />
         <div className="absolute bottom-0 right-1/4 w-[400px] h-[400px] bg-neon-purple/5 blur-[120px] rounded-full" />
      </div>

      <div className="relative z-10 container mx-auto px-4 py-8 max-w-7xl">

        {/* Header Black Neon */}
        <header className="flex flex-col items-center mb-12">
          <div className="group relative mb-4">
            <h1 className="text-5xl md:text-7xl font-display font-black tracking-tighter text-white transition-all duration-700">
              MISS<span className="text-neon-blue text-neon-glow">CLICKS</span>
            </h1>
            <div className="absolute -bottom-2 left-0 w-full h-[1px] bg-gradient-to-r from-transparent via-neon-blue to-transparent"></div>
          </div>
          <p className="font-mono text-[10px] md:text-xs text-neon-blue tracking-[0.5em] uppercase opacity-70 flex items-center gap-3">
             <span className="w-1.5 h-1.5 bg-neon-blue rounded-full animate-ping"></span>
             Combat Monitoring System // MJR-Core
          </p>
        </header>

        {/* Custom Navigation Tabs */}
        <div className="flex justify-center mb-12">
            <div className="inline-flex p-1.5 bg-zinc-950 border border-white/5 rounded-2xl gap-1.5 backdrop-blur-xl shadow-2xl">
                {tabs.map((tab) => {
                  const isActive = activeTab === tab.id;
                  let activeClass = "";

                  if (tab.id === TimeFrame.BLACK_LIST) {
                    activeClass = isActive ? "bg-red-600 shadow-neon-red text-white" : "hover:text-red-500";
                  } else if (tab.id === TimeFrame.ALL_TIME) {
                    activeClass = isActive ? "bg-yellow-500 shadow-[0_0_15px_rgba(234,179,8,0.4)] text-black" : "hover:text-yellow-400";
                  } else {
                    activeClass = isActive ? "bg-neon-blue shadow-neon-blue text-black" : "hover:text-neon-blue";
                  }

                  return (
                    <button
                      key={tab.id}
                      onClick={() => setActiveTab(tab.id)}
                      className={`
                        relative flex flex-col items-center justify-center px-4 py-2.5 rounded-xl transition-all duration-500 min-w-[90px] md:min-w-[110px]
                        ${isActive ? activeClass : "text-zinc-600"}
                      `}
                    >
                      <span className="font-display font-bold text-[11px] md:text-xs uppercase tracking-tight">{tab.label}</span>
                      <span className={`text-[8px] font-mono mt-0.5 uppercase opacity-60`}>{tab.subLabel}</span>
                    </button>
                  );
                })}
            </div>
        </div>

        {/* Dynamic Content */}
        {loading ? (
          <div className="flex flex-col justify-center items-center h-64 gap-4">
            <div className="w-10 h-10 border-2 border-neon-blue/20 border-t-neon-blue rounded-full animate-spin"></div>
            <span className="font-mono text-[10px] text-neon-blue tracking-widest animate-pulse">BOOTING SYSTEM...</span>
          </div>
        ) : error ? (
            <div className="text-center p-12 bg-zinc-950 border border-red-500/20 rounded-2xl max-w-lg mx-auto shadow-neon-red">
                <p className="text-red-500 font-display font-bold mb-4 uppercase tracking-widest">Protocol Failure</p>
                <p className="text-zinc-500 text-xs font-mono leading-relaxed mb-8">{error}</p>
                <button onClick={() => loadData()} className="px-8 py-2 bg-red-600 text-white rounded font-bold text-xs uppercase hover:bg-red-500 transition-colors">
                    Re-establish Link
                </button>
            </div>
        ) : (
          <main className="animate-fade-in relative">
            {activeTab === TimeFrame.OVERVIEW ? (
                 overviewData && <Overview data={overviewData} />
            ) : activeTab === TimeFrame.BLACK_LIST ? (
                 <BlackListView rawData={rawData} />
            ) : activeTab === TimeFrame.ALL_TIME ? (
                 <LegendsView players={rankedPlayers} />
            ) : (
                <div className="space-y-8">
                    <div className="text-center">
                        <h2 className="text-2xl font-display font-black text-white uppercase tracking-tighter">
                          Rank <span className="text-neon-blue">//</span> {tabs.find(t => t.id === activeTab)?.label}
                        </h2>
                    </div>
                    {rankedPlayers.length === 0 ? (
                        <div className="text-center py-32 bg-zinc-950/50 rounded-2xl border border-white/5 border-dashed">
                            <p className="font-display text-zinc-600 text-lg uppercase tracking-widest">No signals found</p>
                        </div>
                    ) : (
                        <>
                            <Podium players={rankedPlayers} />
                            <RankingList players={rankedPlayers} />
                        </>
                    )}
                </div>
            )}
          </main>
        )}
      </div>

      {/* Floating Refresh */}
      <button 
        onClick={() => loadData(true)}
        disabled={isRefreshing || loading}
        className="fixed bottom-8 right-8 w-14 h-14 bg-black border border-white/10 rounded-full flex items-center justify-center text-zinc-500 hover:text-neon-blue hover:border-neon-blue hover:shadow-neon-blue transition-all z-50 group active:scale-95"
      >
        <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" 
             className={`w-6 h-6 ${isRefreshing ? 'animate-spin' : 'group-hover:rotate-180 transition-transform duration-1000'}`}>
          <path strokeLinecap="round" strokeLinejoin="round" d="M16.023 9.348h4.992v-.001M2.985 19.644v-4.992m0 0h4.992m-4.993 0l3.181 3.183a8.25 8.25 0 0013.803-3.7M4.031 9.865a8.25 8.25 0 0113.803-3.7l3.181 3.182m0-4.991v4.99" />
        </svg>
      </button>

      <footer className="text-center py-12 border-t border-white/5 mt-20">
         <p className="font-mono text-[9px] text-zinc-700 tracking-[0.4em] uppercase">
            MissclicKS Engine v2.5 // Developed for MJR Community
         </p>
      </footer>
    </div>
  );
};

export default App;

import React from 'react';
import { RankedPlayer } from '../types';
import { TrophyIcon } from './NeonIcons';

interface PodiumProps {
  players: RankedPlayer[];
}

const PodiumStep: React.FC<{ player: RankedPlayer; place: 1 | 2 | 3 }> = ({ player, place }) => {
  const isFirst = place === 1;

  const colors = {
    1: { border: 'border-neon-purple', shadow: 'shadow-neon-purple', text: 'text-neon-purple', bg: 'bg-neon-purple/5' },
    2: { border: 'border-neon-blue', shadow: 'shadow-neon-blue', text: 'text-neon-blue', bg: 'bg-neon-blue/5' },
    3: { border: 'border-neon-green', shadow: 'shadow-neon-green', text: 'text-neon-green', bg: 'bg-neon-green/5' }
  };

  const s = colors[place];
  const containerHeight = isFirst ? 'h-[240px]' : 'h-[200px]';
  const order = isFirst ? 'order-2 scale-110 z-20' : place === 2 ? 'order-1' : 'order-3';

  return (
    <div className={`flex-1 flex flex-col items-center ${order} transition-all duration-700 max-w-[33%]`}>

      {/* Head Section */}
      <div className={`
        relative rounded-2xl border-2 ${s.border} bg-black flex items-center justify-center
        ${isFirst ? 'w-24 h-24 mb-[-40px]' : 'w-20 h-20 mb-[-35px]'}
        z-30 ${s.shadow}
      `}>
        <span className={`font-display font-black ${isFirst ? 'text-3xl' : 'text-2xl'} text-white`}>
          {player.name.substring(0, 2).toUpperCase()}
        </span>
        {isFirst && (
          <div className="absolute -top-8 animate-bounce">
            <TrophyIcon className="w-10 h-10 text-yellow-400 drop-shadow-[0_0_8px_rgba(255,215,0,0.6)]" />
          </div>
        )}
        <div className={`absolute -bottom-3 px-3 py-0.5 bg-black border ${s.border} ${s.text} text-[10px] font-black rounded-full shadow-xl`}>
          RANK 0{place}
        </div>
      </div>

      {/* Body Section */}
      <div className={`
        relative w-full ${containerHeight} ${s.bg} border ${s.border}
        rounded-3xl flex flex-col items-center justify-center pt-12 pb-6 px-4
        backdrop-blur-xl overflow-hidden
      `}>
        {/* Decorative Grid inside card */}
        <div className="absolute inset-0 opacity-10 bg-[url('https://www.transparenttextures.com/patterns/carbon-fibre.png')] pointer-events-none"></div>

        <div className="relative z-10 w-full text-center mb-auto">
            <h3 className={`font-display font-black text-white leading-tight break-words px-1 ${isFirst ? 'text-lg md:text-xl' : 'text-sm md:text-base'}`}>
              {player.name}
            </h3>
        </div>

        <div className="relative z-10 mt-4 text-center">
            <span className="text-zinc-600 text-[9px] uppercase tracking-[0.2em] font-mono block mb-1">Combat Score</span>
            <div className={`font-mono font-black ${isFirst ? 'text-4xl' : 'text-3xl'} ${s.text} leading-none`}>
              {player.totalKS}
            </div>
        </div>

        {/* Intensity Light Bar */}
        <div className={`absolute bottom-0 left-0 w-full h-[2px] ${s.text.replace('text-', 'bg-')} ${s.shadow}`} />
      </div>
    </div>
  );
};

export const Podium: React.FC<PodiumProps> = ({ players }) => {
  if (players.length === 0) return null;
  const first = players[0];
  const second = players.length > 1 ? players[1] : null;
  const third = players.length > 2 ? players[2] : null;

  return (
    <div className="w-full max-w-4xl mx-auto px-4 py-10">
      <div className="flex flex-row items-end justify-center gap-4 md:gap-8">
        {second ? <PodiumStep player={second} place={2} /> : <div className="flex-1 max-w-[33%]" />}
        {first ? <PodiumStep player={first} place={1} /> : <div className="flex-1 max-w-[33%]" />}
        {third ? <PodiumStep player={third} place={3} /> : <div className="flex-1 max-w-[33%]" />}
      </div>
    </div>
  );
};

import React from 'react';
import { OverviewData } from '../types';

interface OverviewProps {
  data: OverviewData;
}

