  const maxWeekly = Math.max(...data.weeklyDistribution, 1);
  const maxTrend = Math.max(...data.dailyTrend.map(d => d.count), 1);
  const maxRankCount = Math.max(...data.killsByRank.map(r => r.count), 1);
  const maxRespawnCount = Math.max(...data.topRespawns.map(r => r.count), 1);
  const daysOfWeek = ['Dom', 'Seg', 'Ter', 'Qua', 'Qui', 'Sex', 'Sáb'];

  return (
    <div className="w-full max-w-6xl mx-auto px-4 pb-12 animate-fade-in space-y-10">

      {/* Mini Stats Grid */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
        <StatCard label="Total Combat" value={data.totalKills.toLocaleString()} color="purple" />
        <StatCard label="Avg Ops/Day" value={data.avgKillsPerDay.toString()} color="blue" />
        <StatCard label="Elite Tasks" value={data.weightDistribution.heavy.toString()} color="green" />
        <StatCard label="Peak Cycle" value={data.busiestDay.substring(0, 3)} color="white" />
      </div>

      {/* Main Stats Row */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-8">

        {/* Activity Feed */}
        <div className="md:col-span-2 bg-zinc-950 border border-white/5 rounded-3xl p-8 relative overflow-hidden group shadow-2xl">
            <div className="absolute top-0 right-0 w-40 h-40 bg-neon-purple/10 blur-[60px] rounded-full pointer-events-none" />
            <h3 className="text-neon-purple font-display text-sm font-black uppercase tracking-widest mb-8 flex items-center gap-3">
                <span className="w-2 h-2 bg-neon-purple rounded-full shadow-neon-purple"></span>
                LIVE COMBAT FEED
            </h3>
            <div className="space-y-3 font-mono text-xs overflow-y-auto max-h-[300px] pr-4 custom-scrollbar">
                {data.recentActivity.map((log, i) => {
                    const d = new Date(log.date);
                    const time = `${d.getHours().toString().padStart(2, '0')}:${d.getMinutes().toString().padStart(2, '0')}`;
                    return (
                        <div key={i} className="flex items-center justify-between py-3 border-b border-white/5 hover:bg-white/5 px-4 rounded-xl transition-all">
                            <div className="flex items-center gap-4">
                                <span className="text-zinc-600">[{time}]</span>
                                <span className="text-white font-bold">{log.player}</span>
