                            <div className="flex items-center gap-6">
                                <span className="text-zinc-700 hidden sm:block italic">{log.respawn}</span>
                                <span className={`font-black ${log.ks > 1 ? 'text-neon-purple' : 'text-zinc-400'}`}>+{log.ks} KS</span>
                            </div>
                        </div>
                    );
                })}
            </div>
        </div>

        {/* Server Domination */}
        <div className="bg-zinc-950 border border-white/5 rounded-3xl p-8 relative overflow-hidden shadow-2xl">
            <h3 className="text-neon-blue font-display text-sm font-black uppercase tracking-widest mb-8">SERVER WARLORDS</h3>
            <div className="space-y-6">
                {data.dominationStats.map((stat, i) => (
                    <div key={i} className="space-y-2">
                        <div className="flex justify-between font-mono text-[10px] text-zinc-400">
                            <span className="font-bold text-white uppercase">{stat.name}</span>
                            <span className="text-neon-blue">{stat.percentage.toFixed(1)}%</span>
                        </div>
                        <div className="w-full bg-black h-1 rounded-full overflow-hidden">
                            <div style={{ width: `${stat.percentage}%` }} className="h-full bg-neon-blue shadow-neon-blue" />
                        </div>
                    </div>
                ))}
            </div>
        </div>
      </div>

      {/* Weekly Cycle Graph */}
      <div className="bg-zinc-950 border border-white/5 rounded-3xl p-8 shadow-2xl">
            <h3 className="text-neon-green font-display text-sm font-black uppercase tracking-widest mb-10">WEEKLY OPS INTENSITY</h3>
            <div className="flex items-end justify-between h-40 gap-3 md:gap-8 px-2">
                {daysOfWeek.map((day, i) => {
                    const count = data.weeklyDistribution[i];
                    const height = (count / maxWeekly) * 100;
                    return (
                        <div key={i} className="flex-1 flex flex-col items-center group relative">
                            <div className="absolute -top-8 opacity-0 group-hover:opacity-100 transition-all font-mono text-[10px] text-neon-green font-black">
                                {count}
                            </div>
                            <div style={{ height: `${height}%` }} className="w-full max-w-[20px] bg-zinc-900 rounded-t-lg relative transition-all duration-500 group-hover:bg-neon-green/40">
