                    ))}
                </div>
            </div>

            <div className="bg-zinc-950 border border-white/5 rounded-3xl p-8">
                <h3 className="text-neon-green font-display text-sm font-black uppercase tracking-widest mb-8 text-center">TRAFFIC HOTZONES</h3>
                <div className="space-y-4 max-h-[300px] overflow-y-auto pr-2 custom-scrollbar">
                    {data.topRespawns.map((item, i) => (
                        <div key={i} className="flex items-center gap-4">
                            <span className="w-20 font-mono text-[10px] text-zinc-500 uppercase truncate text-right">{item.name}</span>
                            <div className="flex-1 h-1.5 bg-black rounded-full overflow-hidden">
                                <div style={{ width: `${(item.count / maxRespawnCount) * 100}%` }} className="h-full bg-neon-green shadow-neon-green" />
                            </div>
                            <span className="w-8 font-mono text-[10px] text-white text-right font-bold">{item.count}</span>
                        </div>
                    ))}
                </div>
            </div>
      </div>

    </div>
  );
};

const StatCard: React.FC<{ label: string; value: string; color: 'blue' | 'purple' | 'green' | 'white' }> = ({ label, value, color }) => {
    const colors = {
        blue: 'text-neon-blue border-neon-blue/20 bg-neon-blue/5',
        purple: 'text-neon-purple border-neon-purple/20 bg-neon-purple/5',
        green: 'text-neon-green border-neon-green/20 bg-neon-green/5',
        white: 'text-white border-white/10 bg-white/5'
