interface BlackListViewProps {
  rawData: RawDataRow[];
  overviewData: OverviewData | null;
}

export const BlackListView: React.FC<BlackListViewProps> = ({ rawData, overviewData }) => {
  // Filtra jogadores banidos permanentemente (Ranking original)
  const blacklisted = Array.from(new Set(
    rawData
      .filter(row => 
        row.playerRank.toLowerCase().includes('banned') || 
        row.playerRank.toLowerCase().includes('toxic') ||
        row.playerRank.toLowerCase().includes('blacklist')
      )
      .map(row => row.player)
  )).map(name => {
      const playerLogs = rawData.filter(r => r.player === name);
      return {
          name,
          reason: playerLogs[0].playerRank,
          lastSeen: playerLogs[playerLogs.length - 1].date
