                                  <div>
                                      <h4 className="text-gray-400 font-bold text-sm group-hover:text-white">{target.name}</h4>
                                      <span className="text-[10px] font-mono text-gray-600 uppercase group-hover:text-gray-400">{target.reason}</span>
                                  </div>
                              </div>
                              <span className="text-[9px] font-mono text-gray-800">{new Date(target.lastSeen).toLocaleDateString()}</span>
                          </div>
                      ))}
                  </div>
              )}
          </div>
      </div>

      <div className="text-center py-4 border-t border-gray-900/50">
          <p className="text-gray-700 text-[10px] leading-relaxed font-mono uppercase tracking-widest">
            Monitoramento tático MJR - Acesso Restrito
          </p>
      </div>

    </div>
  );
};

import React from 'react';
import { RawDataRow, OverviewData } from '../types';
import { SkullIcon, AlertIcon } from './NeonIcons';

interface BlackListViewProps {
  rawData: RawDataRow[];
  overviewData: OverviewData | null;
}

export const BlackListView: React.FC<BlackListViewProps> = ({ rawData, overviewData }) => {
  const huntedIntel = overviewData?.huntedIntel;
  const maxFreq = huntedIntel ? Math.max(...huntedIntel.timeDistribution, 1) : 1;

  // Divisões do dia para tornar o gráfico intuitivo
  const getTimePeriod = (hour: number) => {
    if (hour >= 0 && hour < 6) return 'Madrugada';
    if (hour >= 6 && hour < 12) return 'Manhã';
    if (hour >= 12 && hour < 18) return 'Tarde';
    return 'Noite';
  };

  const now = new Date();

  return (
    <div className="w-full max-w-5xl mx-auto animate-fade-in pb-20 px-4 space-y-8">

      {/* SEÇÃO DE INTELIGÊNCIA: PADRÕES DE HUNTEDS (Últimos 30 Dias) */}
      <div className="bg-neon-surface border border-neon-blue/20 rounded-2xl overflow-hidden shadow-[0_0_50px_rgba(0,243,255,0.05)]">
          <div className="bg-gradient-to-r from-neon-blue/10 to-transparent p-6 border-b border-gray-800 flex flex-col md:flex-row md:items-center justify-between gap-4">
              <div className="flex items-center gap-3">
                  <div className="w-2.5 h-2.5 bg-neon-blue rounded-full animate-pulse shadow-[0_0_10px_#00f3ff]"></div>
                  <h2 className="font-display font-black text-white tracking-widest uppercase text-xl md:text-2xl">
                    Inteligência de Alvos
                  </h2>
              </div>
              <div className="flex flex-col md:text-right">
                <span className="font-mono text-[10px] text-neon-blue uppercase tracking-[0.2em] font-bold">Relatório de Atividade Recente</span>
                <span className="text-[9px] text-gray-500 font-mono italic">Baseado nos últimos 30 dias de avistamentos</span>
              </div>
          </div>

          <div className="p-6 space-y-12">

              {/* Parte 1: Lista de Alvos, Horários e Status de Evasão */}
              <div className="space-y-4">
                  <div className="flex items-center gap-2 mb-2">
                     <div className="h-4 w-1 bg-neon-blue rounded-full"></div>
                     <h3 className="text-gray-300 font-display text-xs uppercase tracking-widest">Alvos Identificados: Perfil Tático</h3>
                  </div>
                  <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                      {huntedIntel?.targets.map((target, i) => {
                          const lastSeenDate = new Date(target.lastSeen);
                          const diffMs = now.getTime() - lastSeenDate.getTime();
                          const diffDays = Math.floor(diffMs / (1000 * 60 * 60 * 24));
                          const isInactive = diffDays > 7;

                          return (
                              <div key={i} className={`bg-black/40 border ${isInactive ? 'border-gray-800 opacity-80' : 'border-gray-800'} rounded-xl p-5 group hover:border-neon-blue/40 transition-all flex flex-col relative overflow-hidden`}>

                                  {/* Status de Evasão Badge */}
                                  <div className="absolute top-0 right-0">
                                      <div className={`text-[8px] font-black uppercase px-2 py-0.5 rounded-bl-lg font-mono tracking-tighter shadow-lg ${isInactive ? 'bg-zinc-800 text-zinc-500' : 'bg-neon-blue text-black animate-pulse'}`}>
                                          {isInactive ? 'Inativo / Oculto' : 'Ativo no Radar'}
                                      </div>
                                  </div>

                                  <div className="flex justify-between items-start mb-4 mt-2">
                                      <span className={`text-base font-black truncate pr-2 transition-colors ${isInactive ? 'text-gray-500' : 'text-white group-hover:text-neon-blue'}`}>
                                          {target.name}
                                      </span>
                                      <span className="bg-gray-800 text-gray-400 text-[10px] px-2 py-0.5 rounded-full font-mono font-bold">x{target.count}</span>
                                  </div>

                                  <div className="space-y-3 flex-1">
                                      {/* Horário de Pico */}
                                      <div className="flex items-center justify-between py-2 border-b border-gray-800/50">
                                          <span className="text-[10px] text-gray-500 uppercase font-mono tracking-tighter font-bold">Horário Usual:</span>
                                          <span className={`text-xs font-mono font-black ${isInactive ? 'text-gray-600' : 'text-neon-blue'}`}>{target.peakHour}</span>
                                      </div>

                                      {/* Status Temporal */}
                                      <div className="flex items-center justify-between py-2 border-b border-gray-800/50">
                                          <span className="text-[10px] text-gray-500 uppercase font-mono tracking-tighter font-bold">Último Sinal:</span>
                                          <span className={`text-[10px] font-mono font-bold ${isInactive ? 'text-orange-900' : 'text-neon-green/80'}`}>
                                              {diffDays === 0 ? 'HOJE' : `${diffDays} DIA${diffDays > 1 ? 'S' : ''} ATRÁS`}
                                          </span>
                                      </div>

                                      {/* Top Locais */}
                                      <div className="pt-1">
                                          <span className="text-[9px] text-gray-600 uppercase font-mono block mb-2 tracking-widest font-bold">Zonas de Avistamento (Top 3)</span>
                                          <div className="space-y-1.5">
                                              {target.topLocations.map((loc, idx) => (
                                                  <div key={idx} className="flex items-center justify-between bg-zinc-900/40 p-1.5 rounded-md border border-gray-800/30">
                                                      <span className={`text-[10px] truncate max-w-[120px] ${isInactive ? 'text-zinc-600' : 'text-zinc-400'}`} title={loc.name}>
                                                          {idx + 1}. {loc.name}
                                                      </span>
                                                      <span className={`text-[9px] font-mono ${isInactive ? 'text-zinc-700' : 'text-neon-blue/70'}`}>{loc.count}x</span>
                                                  </div>
                                              ))}
                                          </div>
                                      </div>
                                  </div>
                              </div>
                          );
                      })}
                      {(!huntedIntel || huntedIntel.targets.length === 0) && (
                          <div className="col-span-full py-12 text-center opacity-30 border border-dashed border-gray-800 rounded-xl">
                              <p className="font-mono text-xs">Nenhum alvo detectado no radar recentemente.</p>
                          </div>
                      )}
                  </div>
              </div>

              {/* Parte 2: Gráfico de Horários (Strike Windows) */}
              <div className="space-y-6">
                  <div className="flex items-center gap-2 mb-2">
                     <div className="h-4 w-1 bg-neon-blue rounded-full"></div>
                     <h3 className="text-gray-300 font-display text-xs uppercase tracking-widest">Mapa de Calor: Intensidade por Horário</h3>
                  </div>

                  <div className="bg-black/30 p-8 rounded-2xl border border-gray-800/50 relative">
                    <div className="absolute inset-x-8 top-8 bottom-20 flex flex-col justify-between pointer-events-none opacity-5">
                        <div className="w-full h-px bg-white"></div>
                        <div className="w-full h-px bg-white"></div>
                        <div className="w-full h-px bg-white"></div>
                    </div>

                    <div className="relative h-40 flex items-end justify-between gap-1.5 md:gap-3 z-10">
                        {huntedIntel?.timeDistribution.map((freq, hour) => {
                            const height = (freq / maxFreq) * 100;
                            const isPeak = freq === maxFreq && freq > 0;

                            return (
                                <div key={hour} className="flex-1 flex flex-col items-center group relative h-full justify-end">
                                    <div className="absolute -top-10 left-1/2 -translate-x-1/2 opacity-0 group-hover:opacity-100 transition-all bg-neon-blue text-black text-[10px] font-bold px-2 py-1 rounded-md z-20 pointer-events-none whitespace-nowrap shadow-[0_0_15px_rgba(0,243,255,0.4)]">
                                        {freq} Incidências
                                    </div>

                                    <div 
                                        style={{ height: `${Math.max(height, 2)}%` }}
                                        className={`w-full rounded-t-md transition-all duration-700 
                                            ${freq > 0 
                                                ? (isPeak ? 'bg-white shadow-[0_0_20px_white]' : 'bg-neon-blue shadow-[0_0_15px_rgba(0,243,255,0.5)]') 
                                                : 'bg-gray-800 opacity-20'}`}
                                    />

                                    <div className="mt-4 flex flex-col items-center">
                                        <span className={`text-[9px] font-mono transition-colors ${freq > 0 ? 'text-neon-blue' : 'text-gray-700'}`}>
                                            {hour.toString().padStart(2, '0')}h
                                        </span>
                                        {hour % 6 === 0 && (
                                            <span className="absolute -bottom-6 text-[8px] uppercase tracking-tighter text-gray-600 font-bold whitespace-nowrap">
                                                {getTimePeriod(hour)}
                                            </span>
                                        )}
                                    </div>
                                </div>
                            );
                        })}
                    </div>
                    <div className="h-10"></div>
                  </div>
              </div>

          </div>
      </div>

      <div className="text-center py-4 border-t border-gray-900/50">
          <p className="text-gray-700 text-[10px] leading-relaxed font-mono uppercase tracking-widest">
            Monitoramento tático MJR - Acesso Restrito
          </p>
      </div>

    </div>
  );
};

import React, { useEffect, useState, useCallback } from 'react';
import { TargetIcon } from './components/NeonIcons';
import { Podium } from './components/Podium';
import { RankingList } from './components/RankingList';
import { Overview } from './components/Overview';
import { LegendsView } from './components/LegendsView'; 
import { BlackListView } from './components/BlackListView';
import { aggregateData, fetchAndParseData, getOverviewStats } from './services/csvService';
import { RankedPlayer, RawDataRow, TimeFrame, OverviewData } from './types';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<TimeFrame>(TimeFrame.OVERVIEW);
  const [rawData, setRawData] = useState<RawDataRow[]>([]);
  const [rankedPlayers, setRankedPlayers] = useState<RankedPlayer[]>([]);
  const [overviewData, setOverviewData] = useState<OverviewData | null>(null);
  const [loading, setLoading] = useState(true);
  const [isRefreshing, setIsRefreshing] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const loadData = useCallback(async (isManualRefresh = false) => {
    if (isManualRefresh) setIsRefreshing(true);
    else setLoading(true);

    setError(null);
    try {
      const data = await fetchAndParseData();
      if (data.length === 0) {
        setError("Não foi possível carregar os dados. Verifique a planilha.");
      } else {
        setRawData(data);
        setOverviewData(getOverviewStats(data));
        if (activeTab !== TimeFrame.OVERVIEW && activeTab !== TimeFrame.BLACK_LIST) {
          setRankedPlayers(aggregateData(data, activeTab));
        }
      }
    } catch (err) {
      setError("Erro de conexão ao banco de dados combatente.");
    } finally {
      setLoading(false);
      setIsRefreshing(false);
    }
  }, [activeTab]);

  useEffect(() => { loadData(); }, []);

  useEffect(() => {
    if (rawData.length > 0 && activeTab !== TimeFrame.OVERVIEW && activeTab !== TimeFrame.BLACK_LIST) {
      setRankedPlayers(aggregateData(rawData, activeTab));
    }
  }, [activeTab, rawData]);

  const tabs = [
    { id: TimeFrame.OVERVIEW, label: 'Overview', subLabel: 'Estatísticas' },
    { id: TimeFrame.BLACK_LIST, label: 'Black List', subLabel: 'Hunteds' },
    { id: TimeFrame.DAILY, label: 'Hoje', subLabel: 'Últimas 24h' },
    { id: TimeFrame.WEEKLY, label: 'Semana', subLabel: 'Últimos 7 dias' },
    { id: TimeFrame.MONTHLY, label: 'Mês', subLabel: 'Últimos 30 dias' },
    { id: TimeFrame.ALL_TIME, label: 'Legends', subLabel: 'Hall da Fama' },
  ];

  return (
    <div className="min-h-screen bg-neon-dark text-white selection:bg-neon-blue selection:text-black font-sans overflow-x-hidden">
      <div className="fixed top-0 left-0 w-full h-full pointer-events-none overflow-hidden z-0">
         <div className="absolute -top-20 -left-20 w-96 h-96 bg-neon-purple opacity-10 blur-[100px] rounded-full" />
         <div className="absolute top-1/2 right-0 w-80 h-80 bg-neon-blue opacity-10 blur-[120px] rounded-full" />
      </div>

      <div className="relative z-10 container mx-auto px-4 py-8">
        {/* MJR Badge - Top Right */}
        <div className="absolute top-4 right-4 md:top-8 md:right-8 flex flex-col items-center justify-center w-14 h-14 md:w-16 md:h-16 border border-neon-blue/40 bg-black/40 backdrop-blur-md rounded-xl shadow-[0_0_15px_rgba(0,243,255,0.15)] group transition-all hover:border-neon-blue hover:shadow-[0_0_20px_rgba(0,243,255,0.3)]">
          <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="currentColor" className="w-8 h-8 text-neon-blue transition-transform group-hover:-translate-y-1">
            <path fillRule="evenodd" d="M11.47 7.72a.75.75 0 011.06 0l7.5 7.5a.75.75 0 11-1.06 1.06L12 9.31l-6.97 6.97a.75.75 0 01-1.06-1.06l7.5-7.5z" clipRule="evenodd" />
          </svg>
          <span className="text-[11px] md:text-xs font-display font-black text-neon-blue tracking-tighter -mt-1 group-hover:scale-110 transition-transform">MJR</span>
        </div>

        <header className="flex flex-col items-center mb-10">
          <div className="relative mb-2">
            <h1 className="text-4xl md:text-6xl font-display font-black tracking-tighter text-transparent bg-clip-text bg-gradient-to-r from-neon-blue via-white to-neon-purple drop-shadow-lg">
              MissclicKS
            </h1>
            <div className="absolute -inset-1 blur-lg bg-neon-blue opacity-20 animate-pulse"></div>
          </div>
          <p className="text-neon-blue tracking-widest text-xs uppercase opacity-80 flex items-center gap-2">
            <TargetIcon className="w-4 h-4" /> KS Tracker
          </p>
        </header>

        <div className="flex justify-center mb-10">
            <div className="flex flex-wrap justify-center p-1 bg-neon-surface border border-gray-800 rounded-xl gap-1">
                {tabs.map((tab) => (
                <button
                    key={tab.id}
                    onClick={() => setActiveTab(tab.id)}
                    className={`
                    relative px-4 md:px-6 py-2 rounded-lg transition-all duration-300 flex flex-col items-center justify-center min-w-[100px]
                    ${activeTab === tab.id 
                        ? (tab.id === TimeFrame.ALL_TIME 
                            ? 'text-black bg-gradient-to-r from-yellow-400 to-yellow-600 shadow-[0_0_15px_rgba(234,179,8,0.6)]' 
                            : tab.id === TimeFrame.BLACK_LIST 
                                ? 'text-white bg-red-600 shadow-[0_0_20px_rgba(220,38,38,0.6)]' 
                                : 'text-black bg-neon-blue shadow-[0_0_15px_rgba(0,243,255,0.5)]') 
                        : 'text-gray-400 hover:text-white hover:bg-white/5'}
                    `}
                >
                    <span className="font-display font-bold text-sm uppercase">{tab.label}</span>
                    <span className={`text-[10px] ${activeTab === tab.id ? 'text-white/80 font-bold' : 'text-gray-600'}`}>{tab.subLabel}</span>
                </button>
                ))}
            </div>
        </div>

        {loading ? (
          <div className="flex justify-center items-center h-64">
            <div className="w-12 h-12 border-4 border-neon-blue border-t-transparent rounded-full animate-spin"></div>
          </div>
        ) : error ? (
            <div className="text-center p-8 bg-neon-surface border border-red-500/50 rounded-xl max-w-lg mx-auto">
                <p className="text-red-400 font-bold mb-2">Erro de Sistema</p>
                <p className="text-gray-400 text-sm mb-4">{error}</p>
                <button onClick={() => loadData()} className="mt-4 px-6 py-2 bg-red-500/20 hover:bg-red-500/40 text-red-300 rounded border border-red-500/50 transition-colors">Tentar Novamente</button>
            </div>
        ) : (
          <main className="animate-fade-in">
            {activeTab === TimeFrame.OVERVIEW ? (
                 overviewData && <Overview data={overviewData} />
            ) : activeTab === TimeFrame.BLACK_LIST ? (
                 <BlackListView rawData={rawData} overviewData={overviewData} />
            ) : activeTab === TimeFrame.ALL_TIME ? (
                 <LegendsView players={rankedPlayers} />
            ) : (
                <>
                    <div className="mb-4 text-center">
                    <h2 className="text-2xl font-display text-white mb-1">Ranking {tabs.find(t => t.id === activeTab)?.label}</h2>
                    </div>
                    {rankedPlayers.length === 0 ? (
                        <div className="text-center py-20 opacity-50 bg-neon-surface/30 rounded-xl border border-dashed border-gray-800 mx-auto max-w-2xl mt-8">
                            <p className="font-display text-xl text-gray-400">Sem dados para este período.</p>
                        </div>
                    ) : (
                        <>
                            <Podium players={rankedPlayers} />
                            <RankingList players={rankedPlayers} />
                        </>
                    )}
                </>
            )}
          </main>
        )}
      </div>

      <button 
        onClick={() => loadData(true)}
        disabled={isRefreshing || loading}
        className={`fixed bottom-6 right-6 w-14 h-14 bg-neon-surface border border-neon-purple rounded-full flex items-center justify-center text-neon-purple hover:bg-neon-purple hover:text-white transition-all shadow-lg hover:shadow-neon-purple z-50 group ${isRefreshing ? 'cursor-not-allowed opacity-80' : ''}`}
      >
        <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={2} stroke="currentColor" className={`w-7 h-7 ${isRefreshing ? 'animate-spin' : 'group-hover:rotate-180 transition-transform duration-700'}`}>
          <path strokeLinecap="round" strokeLinejoin="round" d="M16.023 9.348h4.992v-.001M2.985 19.644v-4.992m0 0h4.992m-4.993 0l3.181 3.183a8.25 8.25 0 0013.803-3.7M4.031 9.865a8.25 8.25 0 0113.803-3.7l3.181 3.182m0-4.991v4.99" />
        </svg>
      </button>

      <footer className="text-center py-6 text-gray-600 text-xs">
         <p>MissclicKS &copy; {new Date().getFullYear()} // Sistema de Monitoramento MJR</p>
      </footer>
    </div>
  );
};

export default App;
